const http = require('http');
// ─── TENANT PAGES ──────────────────────────────────────────────────────────
const BOXPARK_CHAT = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, viewport-fit=cover\">\n<title>Boxpark Tech Support</title>\n<link rel=\"icon\" href=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/The%20Bench%20by%20Stacked%20(1).png\">\n<link href=\"https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,600;9..144,700&family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600&display=swap\" rel=\"stylesheet\">\n<style>\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\n:root{\n  --brand:#E31E26;--brand-light:#ff4a50;\n  --bg:#111111;--card:#1e1e1e;--border:#2e2e2e;\n  --text:#ffffff;--text-mid:#888888;\n  --green:#2a9d5c;--red:#d64545;\n  --shadow:0 2px 16px rgba(0,0,0,0.5);\n}\nhtml,body{height:100%;height:100dvh;background:var(--bg);font-family:'DM Sans',sans-serif;color:var(--text);overflow:hidden}\n#gate{position:fixed;inset:0;background:var(--bg);display:flex;align-items:center;justify-content:center;z-index:100;padding:24px}\n#gate.hidden{display:none}\n.gate-card{background:var(--card);border-radius:24px;padding:40px 32px;width:100%;max-width:420px;box-shadow:var(--shadow);text-align:center;border:1px solid var(--border)}\n.gate-logo{height:56px;max-width:180px;object-fit:contain;margin-bottom:16px}\n.gate-sub{font-size:13px;color:var(--text-mid);margin-bottom:20px;letter-spacing:0.02em}\n.gate-card h2{font-family:'Fraunces',serif;font-size:22px;margin-bottom:6px}\n.gate-card p{font-size:14px;color:var(--text-mid);margin-bottom:20px;line-height:1.5}\n.gate-input{width:100%;padding:12px 16px;border:1.5px solid var(--border);border-radius:12px;font-family:'DM Sans',sans-serif;font-size:15px;color:var(--text);background:rgba(255,255,255,0.05);margin-bottom:10px;outline:none;transition:border-color 0.2s}\n.gate-input:focus{border-color:var(--brand)}\n.gate-input::placeholder{color:var(--text-mid)}\n.gate-btn{width:100%;padding:14px;background:var(--brand);color:#fff;border:none;border-radius:12px;font-family:'DM Sans',sans-serif;font-size:16px;font-weight:600;cursor:pointer;transition:background 0.2s}\n.gate-btn:hover{background:var(--brand-light)}\n.gate-error{font-size:13px;color:var(--red);margin-top:-6px;margin-bottom:8px;display:none}\n#app{display:flex;flex-direction:column;height:100%;height:100dvh}\nheader{display:flex;align-items:center;justify-content:space-between;padding:14px 20px;background:var(--card);border-bottom:1px solid var(--border);flex-shrink:0}\n.header-logo{height:30px;object-fit:contain}\n.header-actions{display:flex;gap:8px;align-items:center}\n.user-chip{display:flex;align-items:center;gap:8px;background:rgba(255,255,255,0.06);border-radius:20px;padding:6px 12px 6px 8px;font-size:13px;font-weight:500;border:1px solid var(--border)}\n.user-chip .dot{width:8px;height:8px;border-radius:50%;background:var(--green)}\n.icon-btn{background:none;border:none;cursor:pointer;padding:8px;border-radius:10px;color:var(--text-mid);font-size:18px}\n.icon-btn:hover{background:var(--border)}\nmain{flex:1;overflow:hidden;display:flex;flex-direction:column;min-height:0}\n#messages{flex:1;overflow-y:auto;padding:20px 16px 8px;display:flex;flex-direction:column;gap:16px;scroll-behavior:smooth}\n.welcome{display:flex;flex-direction:column;align-items:center;justify-content:center;flex:1;padding:32px 16px;gap:12px;text-align:center}\n.welcome-logo{height:60px;max-width:180px;object-fit:contain;margin-bottom:4px}\n.welcome h2{font-family:'Fraunces',serif;font-size:24px;font-weight:700;line-height:1.2}\n.welcome p{font-size:14px;color:var(--text-mid);margin-bottom:8px}\n.quick-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;width:100%;max-width:360px}\n.quick-btn{background:var(--card);border:1.5px solid var(--border);border-radius:14px;padding:14px 12px;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:500;color:var(--text);cursor:pointer;text-align:left;transition:border-color 0.2s;line-height:1.3}\n.quick-btn:hover{border-color:var(--brand)}\n.quick-btn .emoji{font-size:18px;display:block;margin-bottom:4px}\n.msg{display:flex;align-items:flex-start;gap:10px}\n.msg.user{flex-direction:row-reverse}\n.msg-avatar{width:32px;height:32px;border-radius:50%;flex-shrink:0;background:var(--border);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:600;overflow:hidden}\n.msg-avatar img{width:100%;height:100%;object-fit:contain}\n.msg-bubble{background:var(--card);border-radius:18px 18px 18px 4px;padding:12px 16px;font-size:15px;line-height:1.55;max-width:calc(100% - 80px);border:1px solid var(--border);white-space:pre-wrap}\n.msg.user .msg-bubble{background:var(--brand);color:#fff;border-radius:18px 18px 4px 18px;border:none}\n.ticket-row{display:flex;justify-content:center;margin-top:-4px}\n.ticket-btn{background:var(--card);border:1.5px solid var(--border);border-radius:20px;padding:8px 16px;font-family:'DM Sans',sans-serif;font-size:13px;font-weight:500;color:var(--text-mid);cursor:pointer;transition:border-color 0.2s}\n.ticket-btn:hover{border-color:var(--brand);color:var(--brand)}\n.link-row{display:flex;flex-wrap:wrap;gap:8px;margin-top:-4px;padding-left:42px}\n.link-pill{display:inline-flex;align-items:center;gap:6px;background:var(--brand);border:none;border-radius:20px;padding:8px 14px;font-size:13px;font-weight:600;color:#fff;text-decoration:none;transition:all 0.15s;white-space:nowrap;box-shadow:0 2px 8px rgba(227,30,38,0.3)}\n.link-pill:hover{background:var(--brand-light);transform:translateY(-1px);box-shadow:0 4px 12px rgba(227,30,38,0.4)}\n.link-pill .pill-icon{font-size:13px}\n.typing-bubble{display:flex;align-items:flex-start;gap:10px}\n.dots{display:flex;gap:4px;align-items:center;background:var(--card);border-radius:18px;padding:12px 16px;border:1px solid var(--border)}\n.dot-anim{width:8px;height:8px;border-radius:50%;background:var(--text-mid);animation:bounce 1.2s infinite}\n.dot-anim:nth-child(2){animation-delay:0.2s}.dot-anim:nth-child(3){animation-delay:0.4s}\n@keyframes bounce{0%,60%,100%{transform:translateY(0)}30%{transform:translateY(-6px)}}\n.input-bar{padding:12px 16px;padding-bottom:calc(12px + env(safe-area-inset-bottom));background:var(--card);border-top:1px solid var(--border);flex-shrink:0;display:flex;gap:10px;align-items:flex-end}\n#input{flex:1;padding:12px 16px;background:rgba(255,255,255,0.05);border:1.5px solid var(--border);border-radius:20px;font-family:'DM Sans',sans-serif;font-size:15px;color:var(--text);resize:none;outline:none;max-height:120px;line-height:1.4;transition:border-color 0.2s}\n#input:focus{border-color:var(--brand)}\n#input::placeholder{color:var(--text-mid)}\n#send{width:44px;height:44px;border-radius:50%;background:var(--brand);border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0}\n#send:hover{background:var(--brand-light)}\n#send svg{width:18px;height:18px;fill:#fff}\n#send:disabled{opacity:0.5;cursor:default}\n.drawer-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:50;opacity:0;pointer-events:none;transition:opacity 0.25s}\n.drawer-overlay.open{opacity:1;pointer-events:all}\n.drawer{position:fixed;bottom:0;left:0;right:0;background:var(--card);border-radius:24px 24px 0 0;z-index:51;max-height:70vh;transform:translateY(100%);transition:transform 0.3s cubic-bezier(0.32,0.72,0,1);display:flex;flex-direction:column;border-top:1px solid var(--border)}\n.drawer.open{transform:translateY(0)}\n.drawer-handle{width:40px;height:4px;background:var(--border);border-radius:2px;margin:12px auto 0}\n.drawer-header{padding:16px 20px 12px;font-family:'Fraunces',serif;font-size:18px;font-weight:700;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between}\n.drawer-close{background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-mid);padding:4px}\n.drawer-body{overflow-y:auto;padding:16px 20px;flex:1}\n.history-item{padding:14px 0;border-bottom:1px solid var(--border);cursor:pointer}\n.history-item:last-child{border-bottom:none}\n.history-date{font-size:11px;color:var(--text-mid);margin-bottom:4px}\n.history-preview{font-size:14px;font-weight:500}\n.history-item:hover .history-preview{color:var(--brand)}\n.history-count{font-size:12px;color:var(--text-mid);margin-top:2px}\n.empty-hist{text-align:center;padding:32px 0;color:var(--text-mid);font-size:14px}\n.modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,0.7);z-index:200;display:flex;align-items:flex-end;opacity:0;pointer-events:none;transition:opacity 0.2s}\n.modal-overlay.open{opacity:1;pointer-events:all}\n.modal{background:var(--card);border-radius:24px 24px 0 0;padding:24px 24px calc(24px + env(safe-area-inset-bottom));width:100%;transform:translateY(100%);transition:transform 0.3s cubic-bezier(0.32,0.72,0,1);border-top:1px solid var(--border)}\n.modal-overlay.open .modal{transform:translateY(0)}\n.modal h3{font-family:'Fraunces',serif;font-size:20px;margin-bottom:6px}\n.modal p{font-size:14px;color:var(--text-mid);margin-bottom:20px}\n.modal textarea{width:100%;border:1.5px solid var(--border);border-radius:12px;padding:12px 14px;font-family:'DM Sans',sans-serif;font-size:14px;color:var(--text);background:rgba(255,255,255,0.05);resize:none;height:100px;outline:none;margin-bottom:14px}\n.modal-actions{display:flex;gap:10px}\n.modal-cancel{flex:1;padding:13px;background:rgba(255,255,255,0.07);border:1px solid var(--border);border-radius:12px;font-family:'DM Sans',sans-serif;font-size:15px;font-weight:500;cursor:pointer;color:var(--text)}\n.modal-submit{flex:2;padding:13px;background:var(--brand);border:none;border-radius:12px;font-family:'DM Sans',sans-serif;font-size:15px;font-weight:600;cursor:pointer;color:#fff}\n.toast{position:fixed;bottom:calc(80px + env(safe-area-inset-bottom));left:50%;transform:translateX(-50%) translateY(20px);background:var(--card);color:var(--text);border-radius:20px;padding:10px 20px;font-size:14px;font-weight:500;opacity:0;transition:all 0.3s;z-index:300;white-space:nowrap;border:1px solid var(--border)}\n.toast.show{opacity:1;transform:translateX(-50%) translateY(0)}\n.toast.green{background:var(--green);border:none}\n#messages::-webkit-scrollbar{width:4px}\n#messages::-webkit-scrollbar-thumb{background:var(--border);border-radius:2px}\n</style>\n</head>\n<body>\n\n<div id=\"gate\">\n  <div class=\"gate-card\">\n    <img class=\"gate-logo\" src=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/Stacked%20(3).svg\" alt=\"Boxpark\" style=\"filter:brightness(0) invert(1)\">\n    <p class=\"gate-sub\">Vendor tech support, powered by Stacked</p>\n    <h2>Welcome \u2014 let's get you sorted</h2>\n    <p>Drop your details below and we'll have you chatting in seconds.</p>\n    <input class=\"gate-input\" type=\"text\" id=\"gateName\" placeholder=\"Your name\" autocomplete=\"given-name\">\n    <input class=\"gate-input\" type=\"text\" id=\"gateUnit\" placeholder=\"Unit / stall name\" autocomplete=\"organization\">\n    <input class=\"gate-input\" type=\"email\" id=\"gateEmail\" placeholder=\"Email address\" autocomplete=\"email\">\n    <div class=\"gate-error\" id=\"gateError\">Please fill in all fields with a valid email.</div>\n    <button class=\"gate-btn\" onclick=\"submitGate()\">Start chatting &rarr;</button>\n  </div>\n</div>\n\n<div id=\"app\">\n  <header>\n    <img class=\"header-logo\" src=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/Stacked%20(3).svg\" alt=\"Boxpark\" style=\"filter:brightness(0) invert(1)\">\n    <div class=\"header-actions\">\n      <div class=\"user-chip\"><div class=\"dot\"></div><span id=\"userLabel\">You</span></div>\n      <button class=\"icon-btn\" onclick=\"openHistory()\" title=\"Chat history\">\n        <svg viewBox=\"0 0 24 24\" width=\"20\" height=\"20\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M12 8v4l3 3M12 2a10 10 0 1 0 0 20A10 10 0 0 0 12 2z\"/></svg>\n      </button>\n    </div>\n  </header>\n  <main>\n    <div id=\"messages\">\n      <div class=\"welcome\" id=\"welcome\">\n        <img class=\"welcome-logo\" src=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/Stacked%20(3).svg\" alt=\"Boxpark\" style=\"filter:brightness(0) invert(1)\">\n        <h2>Got a tech problem?<br>Let's fix it.</h2>\n        <p>Ask anything about your tech at Boxpark &mdash; EPOS, payments, WiFi and more.</p>\n        <div class=\"quick-grid\">\n          <button class=\"quick-btn\" onclick=\"quickSend('My card reader is offline')\"><span class=\"emoji\">\ud83d\udcb3</span>Card reader offline</button>\n          <button class=\"quick-btn\" onclick=\"quickSend('My EPOS has crashed mid-service')\"><span class=\"emoji\">\ud83d\udcbb</span>EPOS crashed</button>\n          <button class=\"quick-btn\" onclick=\"quickSend('WiFi is down at my unit')\"><span class=\"emoji\">\ud83d\udcf6</span>WiFi issues</button>\n          <button class=\"quick-btn\" onclick=\"quickSend('My receipt printer is not working')\"><span class=\"emoji\">\ud83d\udda8\ufe0f</span>Printer not working</button>\n        </div>\n      </div>\n    </div>\n  </main>\n  <div class=\"input-bar\">\n    <textarea id=\"input\" placeholder=\"Describe your tech issue&#8230;\" rows=\"1\" onkeydown=\"handleKey(event)\" oninput=\"autoResize(this)\"></textarea>\n    <button id=\"send\" onclick=\"sendMessage()\"><svg viewBox=\"0 0 24 24\"><path d=\"M2 21l21-9L2 3v7l15 2-15 2z\"/></svg></button>\n  </div>\n</div>\n\n<div class=\"drawer-overlay\" id=\"histOverlay\" onclick=\"closeHistory()\"></div>\n<div class=\"drawer\" id=\"histDrawer\">\n  <div class=\"drawer-handle\"></div>\n  <div class=\"drawer-header\"><span>Chat history</span><button class=\"drawer-close\" onclick=\"closeHistory()\">&times;</button></div>\n  <div class=\"drawer-body\" id=\"histBody\"><div class=\"empty-hist\">No previous chats yet.</div></div>\n</div>\n\n<div class=\"modal-overlay\" id=\"ticketOverlay\">\n  <div class=\"modal\">\n    <h3>Raise a support ticket</h3>\n    <p>We'll look into this and get back to you. Add any extra detail below.</p>\n    <textarea id=\"ticketNote\" placeholder=\"Any extra context&#8230;\"></textarea>\n    <div class=\"modal-actions\">\n      <button class=\"modal-cancel\" onclick=\"closeTicketModal()\">Cancel</button>\n      <button class=\"modal-submit\" onclick=\"submitTicket()\">Submit ticket</button>\n    </div>\n  </div>\n</div>\n\n<div class=\"toast\" id=\"toast\"></div>\n\n<script>\nconst TENANT = 'boxpark';\nconst SUPABASE_URL = 'https://yuzlfocqovwhqdpitvxj.supabase.co';\nconst SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inl1emxmb2Nxb3Z3aHFkcGl0dnhqIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzIyODE3OTgsImV4cCI6MjA4Nzg1Nzc5OH0.zN_GOXI8MI9isqnVRCZvxAmU1ZyXIfWvq-P3SkSh4Vk';\nconst ICON_URL = 'https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/The%20Bench%20by%20Stacked%20(1).png';\nlet user=null, msgs=[], convId=null;\n\nwindow.addEventListener('DOMContentLoaded', () => {\n  const saved = localStorage.getItem('user_boxpark');\n  if (saved) { user = JSON.parse(saved); showApp(); }\n});\n\nasync function submitGate() {\n  const name = document.getElementById('gateName').value.trim();\n  const venue = document.getElementById('gateUnit').value.trim();\n  const email = document.getElementById('gateEmail').value.trim();\n  const err = document.getElementById('gateError');\n  if (!name || !venue || !email || !/\\S+@\\S+\\.\\S+/.test(email)) { err.style.display='block'; return; }\n  err.style.display = 'none';\n  user = {name, venue, email};\n  localStorage.setItem('user_boxpark', JSON.stringify(user));\n  try { await sbPost('leads', {name, venue, email, tenant: TENANT}); } catch(e) {}\n  showApp();\n}\n\nfunction showApp() {\n  document.getElementById('gate').classList.add('hidden');\n  document.getElementById('userLabel').textContent = user.name.split(' ')[0];\n  loadHistory();\n}\n\nasync function sbPost(table, data) {\n  return fetch(SUPABASE_URL + '/rest/v1/' + table, {\n    method: 'POST',\n    headers: {'Content-Type':'application/json','apikey':SUPABASE_KEY,'Authorization':'Bearer '+SUPABASE_KEY,'Prefer':'return=representation'},\n    body: JSON.stringify(data)\n  }).then(r => r.json());\n}\n\nfunction handleKey(e) { if (e.key==='Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); } }\nfunction autoResize(el) { el.style.height='auto'; el.style.height=Math.min(el.scrollHeight,120)+'px'; }\nfunction quickSend(text) { document.getElementById('input').value=text; sendMessage(); }\n\nasync function sendMessage() {\n  const input = document.getElementById('input');\n  const text = input.value.trim();\n  if (!text) return;\n  const w = document.getElementById('welcome'); if (w) w.remove();\n  input.value = ''; input.style.height = 'auto';\n  document.getElementById('send').disabled = true;\n  addMsg('user', text);\n  msgs.push({role:'user', content:text});\n  const typing = addTyping();\n  try {\n    const res = await fetch('/boxpark/chat', {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({message:text, history:msgs.slice(-10)})});\n    const data = await res.json();\n    const reply = data.response || \"Sorry, I couldn't get a response. Please try again.\";\n    typing.remove();\n    addMsg('assistant', reply, true);\n    msgs.push({role:'assistant', content:reply});\n    await saveConv();\n  } catch(e) {\n    typing.remove();\n    addMsg('assistant', \"I'm having trouble connecting. Please try again in a moment.\", true);\n  }\n  document.getElementById('send').disabled = false;\n  input.focus();\n}\n\nfunction extractLinks(text) {\n  const urlRegex = /https?:\\/\\/[^\\s)>\\]\"]+/g;\n  const matches = text.match(urlRegex) || [];\n  const seen = new Set();\n  return matches.filter(u => { if (seen.has(u)) return false; seen.add(u); return true; }).slice(0, 4);\n}\nfunction friendlyLabel(url) {\n  const map = {'squareup.com':'\ud83d\udce6 Square help','sumup.com':'\ud83d\udcb3 SumUp help','zettle.com':'\ud83d\udcb3 Zettle help','worldpay.com':'\ud83d\udcb3 Worldpay help','stripe.com':'\ud83d\udcb3 Stripe help','lightspeedhq.com':'\ud83d\udda5 Lightspeed help','tevalis.com':'\ud83d\udda5 Tevalis help','eposnow.com':'\ud83d\udda5 EPOS Now help','vitamojo.com':'\ud83c\udf7d Vita Mojo help','yoello.com':'\ud83d\udcf1 Yoello help','nutritics.com':'\ud83e\udd57 Nutritics help','zonal.co.uk':'\ud83d\udda5 Zonal help','boxpark.co.uk':'\ud83d\udcde Boxpark ops'};\n  try { const host = new URL(url).hostname.replace('www.',''); for (const [k,v] of Object.entries(map)) { if (host.includes(k)) return v; } return '\ud83d\udd17 '+host; } catch(e) { return '\ud83d\udd17 Link'; }\n}\nfunction addMsg(role, content, showTicket=false) {\n  const container = document.getElementById('messages');\n  const wrap = document.createElement('div'); wrap.className = 'msg ' + role;\n  const av = document.createElement('div'); av.className = 'msg-avatar';\n  if (role === 'assistant') {\n    const img = document.createElement('img'); img.src = ICON_URL; img.alt = 'S'; av.appendChild(img);\n  } else {\n    av.textContent = (user?.name||'You')[0].toUpperCase();\n    av.style.cssText = 'background:var(--brand);color:#fff';\n  }\n  const bubble = document.createElement('div'); bubble.className = 'msg-bubble';\n  function renderContent(text) {\n    const esc = text.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');\n    return esc\n      .replace(/\\*\\*(.+?)\\*\\*/g,'<strong>$1</strong>')\n      .replace(/(https?:\\/\\/[^\\s<]+)/g,'<a href=\"$1\" target=\"_blank\" rel=\"noopener\" style=\"color:var(--brand-light);word-break:break-all;\">$1</a>');\n  }\n  if (role === 'assistant') { bubble.innerHTML = renderContent(content); } else { bubble.textContent = content; }\n  wrap.appendChild(av); wrap.appendChild(bubble); container.appendChild(wrap);\n  if (role === 'assistant') {\n    const links = extractLinks(content);\n    if (links.length) {\n      const lr = document.createElement('div'); lr.className = 'link-row';\n      lr.innerHTML = links.map(u => '<a class=\"link-pill\" href=\"'+u+'\" target=\"_blank\" rel=\"noopener\"><span class=\"pill-icon\">\u2197</span>'+friendlyLabel(u)+'</a>').join('');\n      container.appendChild(lr);\n    }\n  }\n  if (role === 'assistant' && showTicket) {\n    const tr = document.createElement('div'); tr.className = 'ticket-row';\n    tr.innerHTML = '<button class=\"ticket-btn\" onclick=\"openTicketModal()\">\ud83c\udfab This didn\\'t solve my issue \u2014 raise a ticket</button>';\n    container.appendChild(tr);\n  }\n  container.scrollTop = container.scrollHeight;\n  return wrap;\n}\n\nfunction addTyping() {\n  const container = document.getElementById('messages');\n  const wrap = document.createElement('div'); wrap.className = 'typing-bubble';\n  const av = document.createElement('div'); av.className = 'msg-avatar';\n  const img = document.createElement('img'); img.src = ICON_URL; av.appendChild(img);\n  const dots = document.createElement('div'); dots.className = 'dots';\n  dots.innerHTML = '<div class=\"dot-anim\"></div><div class=\"dot-anim\"></div><div class=\"dot-anim\"></div>';\n  wrap.appendChild(av); wrap.appendChild(dots); container.appendChild(wrap);\n  container.scrollTop = container.scrollHeight;\n  return wrap;\n}\n\nasync function saveConv() {\n  if (!user || !msgs.length) return;\n  try {\n    const preview = (msgs.find(m => m.role==='user')?.content||'').substring(0,80);\n    const data = {email:user.email, name:user.name, venue:user.venue, messages:msgs, preview, tenant:TENANT, updated_at:new Date().toISOString()};\n    if (convId) {\n      await fetch(SUPABASE_URL+'/rest/v1/conversations?id=eq.'+convId, {method:'PATCH', headers:{'Content-Type':'application/json','apikey':SUPABASE_KEY,'Authorization':'Bearer '+SUPABASE_KEY}, body:JSON.stringify({messages:msgs, updated_at:new Date().toISOString()})});\n    } else {\n      const rows = await sbPost('conversations', data);\n      if (rows && rows[0]) convId = rows[0].id;\n    }\n  } catch(e) {}\n}\n\nasync function loadHistory() {\n  if (!user) return;\n  try {\n    const r = await fetch(SUPABASE_URL+'/rest/v1/conversations?email=eq.'+encodeURIComponent(user.email)+'&tenant=eq.boxpark&order=updated_at.desc&limit=20', {headers:{'apikey':SUPABASE_KEY,'Authorization':'Bearer '+SUPABASE_KEY}});\n    const rows = await r.json();\n    const body = document.getElementById('histBody');\n    if (!rows || !rows.length) { body.innerHTML='<div class=\"empty-hist\">No previous chats yet.</div>'; return; }\n    body.innerHTML = '';\n    rows.forEach(row => {\n      const d = new Date(row.updated_at||row.created_at);\n      const dateStr = d.toLocaleDateString('en-GB', {day:'numeric',month:'short',year:'numeric'});\n      const count = (row.messages||[]).filter(m => m.role==='user').length;\n      const item = document.createElement('div'); item.className='history-item';\n      item.innerHTML = '<div class=\"history-date\">'+dateStr+'</div><div class=\"history-preview\">'+esc(row.preview||'Chat session')+'</div><div class=\"history-count\">'+count+' message'+(count!==1?'s':'')+'</div>';\n      item.onclick = () => loadConv(row);\n      body.appendChild(item);\n    });\n  } catch(e) {}\n}\n\nfunction loadConv(row) {\n  closeHistory();\n  document.getElementById('messages').innerHTML = '';\n  convId = row.id; msgs = row.messages||[];\n  msgs.forEach((m,i) => addMsg(m.role, m.content, m.role==='assistant'&&i===msgs.length-1));\n}\n\nfunction esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }\nfunction openHistory() { loadHistory(); document.getElementById('histOverlay').classList.add('open'); document.getElementById('histDrawer').classList.add('open'); }\nfunction closeHistory() { document.getElementById('histOverlay').classList.remove('open'); document.getElementById('histDrawer').classList.remove('open'); }\nfunction openTicketModal() { document.getElementById('ticketNote').value=''; document.getElementById('ticketOverlay').classList.add('open'); }\nfunction closeTicketModal() { document.getElementById('ticketOverlay').classList.remove('open'); }\n\nasync function submitTicket() {\n  const note = document.getElementById('ticketNote').value.trim();\n  const issue = 'Last question: '+(msgs.filter(m=>m.role==='user').slice(-1)[0]?.content||'')+(note?'\\n\\nExtra detail: '+note:'');\n  try {\n    await sbPost('tickets', {email:user.email, name:user.name, venue:user.venue, issue, conversation:msgs, status:'open', tenant:TENANT});\n    closeTicketModal();\n    showToast('\u2713 Ticket raised \u2014 we\\'ll be in touch!', 'green');\n  } catch(e) { closeTicketModal(); showToast('Something went wrong, please try again.'); }\n}\n\nfunction showToast(msg, type='') {\n  const t = document.getElementById('toast');\n  t.textContent = msg; t.className = 'toast '+type+' show';\n  setTimeout(() => { t.className = 'toast'; }, 3500);\n}\n</script>\n</body>\n</html>";
const BOXPARK_ADMIN = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Boxpark Admin</title>\n<link rel=\"icon\" href=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/The%20Bench%20by%20Stacked%20(1).png\">\n<link href=\"https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,600;9..144,700&family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600&display=swap\" rel=\"stylesheet\">\n<style>\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\n:root{\n  --brand:#E31E26;--brand-light:#ff4a50;\n  --bg:#111111;--card:#1e1e1e;--border:#2e2e2e;\n  --text:#ffffff;--text-mid:#888888;\n  --green:#2a9d5c;--red:#d64545;--blue:#3b82f6;\n  --shadow:0 2px 16px rgba(0,0,0,0.5);\n}\nbody{background:var(--bg);font-family:'DM Sans',sans-serif;color:var(--text);min-height:100vh}\nheader{background:var(--card);border-bottom:1px solid var(--border);padding:16px 32px;display:flex;align-items:center;gap:12px}\n.header-logo{height:30px;object-fit:contain;filter:brightness(0) invert(1)}\n.admin-badge{background:var(--brand);color:#fff;font-size:11px;font-weight:600;padding:3px 8px;border-radius:6px;letter-spacing:0.05em;text-transform:uppercase}\n.container{max-width:1200px;margin:0 auto;padding:32px 24px}\n.tabs{display:flex;gap:4px;background:var(--card);border-radius:14px;padding:4px;margin-bottom:28px;overflow-x:auto;border:1px solid var(--border)}\n.tab{flex:1;min-width:80px;padding:10px 16px;background:none;border:none;border-radius:10px;font-family:'DM Sans',sans-serif;font-size:14px;font-weight:500;color:var(--text-mid);cursor:pointer;white-space:nowrap;transition:all 0.15s}\n.tab.active{background:var(--brand);color:#fff}\n.tab-panel{display:none}.tab-panel.active{display:block}\n.stats{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:16px;margin-bottom:28px}\n.stat{background:var(--card);border-radius:16px;padding:20px;border:1px solid var(--border)}\n.stat-num{font-family:'Fraunces',serif;font-size:32px;font-weight:700;color:var(--brand)}\n.stat-label{font-size:13px;color:var(--text-mid);margin-top:4px}\n.grid2{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px}\n@media(max-width:700px){.grid2{grid-template-columns:1fr}}\n.card{background:var(--card);border-radius:16px;padding:24px;border:1px solid var(--border)}\n.card h3{font-family:'Fraunces',serif;font-size:18px;margin-bottom:16px}\n.bar-row{margin-bottom:10px}\n.bar-label{display:flex;justify-content:space-between;font-size:13px;margin-bottom:4px}\n.bar-track{height:8px;background:var(--border);border-radius:4px;overflow:hidden}\n.bar-fill{height:100%;background:var(--brand);border-radius:4px;transition:width 0.6s ease}\n.bar-fill.blue{background:var(--blue)}\n.empty{color:var(--text-mid);font-size:14px;text-align:center;padding:24px 0}\ntable{width:100%;border-collapse:collapse;font-size:14px}\nth{text-align:left;padding:8px 12px;font-weight:600;color:var(--text-mid);font-size:12px;text-transform:uppercase;letter-spacing:0.05em;border-bottom:2px solid var(--border)}\ntd{padding:10px 12px;border-bottom:1px solid var(--border);vertical-align:top}\ntr:last-child td{border-bottom:none}\ntr:hover td{background:rgba(255,255,255,0.02)}\n.badge{display:inline-block;padding:3px 8px;border-radius:6px;font-size:11px;font-weight:600}\n.badge.open{background:rgba(227,30,38,0.2);color:#ff6b70}\n.badge.closed{background:rgba(42,157,92,0.2);color:#4ade80}\n.badge.indexed{background:rgba(42,157,92,0.2);color:#4ade80}\n.drop-zone{border:2px dashed var(--border);border-radius:16px;padding:48px 32px;text-align:center;cursor:pointer;transition:all 0.2s}\n.drop-zone:hover,.drop-zone.dragging{border-color:var(--brand);background:rgba(227,30,38,0.05)}\n.drop-icon{font-size:40px;margin-bottom:12px}\n.drop-title{font-family:'Fraunces',serif;font-size:18px;margin-bottom:6px}\n.drop-sub{font-size:13px;color:var(--text-mid)}\n#fileInput{display:none}\n.doc-list{display:flex;flex-direction:column;gap:8px;margin-top:16px}\n.doc-item{display:flex;align-items:center;justify-content:space-between;background:rgba(255,255,255,0.03);border-radius:10px;padding:12px 16px;border:1px solid var(--border)}\n.doc-info{display:flex;align-items:center;gap:10px}\n.doc-icon{width:32px;height:32px;background:var(--brand);border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:14px}\n.doc-name{font-size:14px;font-weight:500}\n.doc-date{font-size:11px;color:var(--text-mid)}\n.doc-actions{display:flex;gap:8px;align-items:center}\n.btn-delete{background:var(--red);color:#fff;border:none;border-radius:8px;padding:6px 14px;font-size:12px;font-weight:600;cursor:pointer;font-family:'DM Sans',sans-serif;transition:opacity 0.15s}\n.btn-delete:hover{opacity:0.85}\n.btn-delete:disabled{opacity:0.5;cursor:not-allowed}\n.upload-list{margin-top:20px;display:flex;flex-direction:column;gap:8px}\n.upload-item{background:rgba(255,255,255,0.03);border-radius:10px;padding:12px 16px;display:flex;justify-content:space-between;align-items:center;font-size:13px;border:1px solid var(--border)}\n.progress{height:4px;background:var(--border);border-radius:2px;margin-top:6px;overflow:hidden}\n.progress-bar{height:100%;background:var(--brand);border-radius:2px;width:0;transition:width 0.3s}\n.ticket-msg{font-size:13px;color:var(--text-mid);max-width:300px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n.close-btn{background:var(--green);color:#fff;border:none;border-radius:6px;padding:4px 10px;font-size:11px;font-weight:600;cursor:pointer}\n.notify{position:fixed;bottom:24px;right:24px;background:var(--card);color:var(--text);padding:12px 20px;border-radius:12px;font-size:14px;font-weight:500;transform:translateY(80px);opacity:0;transition:all 0.3s;z-index:99;border:1px solid var(--border)}\n.notify.show{transform:translateY(0);opacity:1}\n.notify.green{background:var(--green);border:none}\n.notify.red{background:var(--red);border:none}\n</style>\n</head>\n<body>\n<header>\n  <img class=\"header-logo\" src=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/Stacked%20(3).svg\" alt=\"Stacked\">\n  <span class=\"admin-badge\">Boxpark Admin</span>\n</header>\n<div class=\"container\">\n  <div class=\"tabs\">\n    <button class=\"tab active\" onclick=\"showTab('dashboard')\">&#x1F4CA; Dashboard</button>\n    <button class=\"tab\" onclick=\"showTab('tickets')\">&#x1F3AB; Tickets</button>\n    <button class=\"tab\" onclick=\"showTab('conversations')\">&#x1F4AC; Conversations</button>\n    <button class=\"tab\" onclick=\"showTab('documents')\">&#x1F4C4; Knowledge Base</button>\n      <button class=\"nav-item\" onclick=\"showTab('podcast')\">&#x1F3A7; Podcast / Video</button>\n  </div>\n  <div class=\"tab-panel active\" id=\"tab-dashboard\">\n    <div class=\"stats\">\n      <div class=\"stat\"><div class=\"stat-num\" id=\"sConvs\">&mdash;</div><div class=\"stat-label\">Conversations</div></div>\n      <div class=\"stat\"><div class=\"stat-num\" id=\"sMsgs\">&mdash;</div><div class=\"stat-label\">Messages sent</div></div>\n      <div class=\"stat\"><div class=\"stat-num\" id=\"sTickets\">&mdash;</div><div class=\"stat-label\">Open tickets</div></div>\n      <div class=\"stat\"><div class=\"stat-num\" id=\"sDocs\">&mdash;</div><div class=\"stat-label\">Documents indexed</div></div>\n    </div>\n    <div class=\"grid2\">\n      <div class=\"card\"><h3>Top topics</h3><div id=\"topicsChart\"><div class=\"empty\">Loading&hellip;</div></div></div>\n      <div class=\"card\"><h3>Top products mentioned</h3><div id=\"vendorsChart\"><div class=\"empty\">Loading&hellip;</div></div></div>\n    </div>\n  </div>\n  <div class=\"tab-panel\" id=\"tab-tickets\"><div class=\"card\"><h3>Support tickets</h3><div id=\"ticketsTable\"><div class=\"empty\">Loading&hellip;</div></div></div></div>\n  <div class=\"tab-panel\" id=\"tab-conversations\"><div class=\"card\"><h3>Recent conversations</h3><div id=\"convsTable\"><div class=\"empty\">Loading&hellip;</div></div></div></div>\n  <div class=\"tab-panel\" id=\"tab-documents\">\n    <div class=\"card\">\n      <div class=\"drop-zone\" id=\"dropZone\" onclick=\"document.getElementById('fileInput').click()\" ondragover=\"dragOver(event)\" ondragleave=\"dragLeave(event)\" ondrop=\"dropFiles(event)\">\n        <div class=\"drop-icon\">&#x1F4C4;</div>\n        <div class=\"drop-title\">Drop files to add to Boxpark's knowledge base</div>\n        <div class=\"drop-sub\">Supports TXT, MD &mdash; up to 10MB each</div>\n      </div>\n      <input type=\"file\" id=\"fileInput\" multiple accept=\".txt,.md\" onchange=\"handleFiles(this.files)\">\n      <div class=\"upload-list\" id=\"uploadList\"></div>\n      <div class=\"doc-list\" id=\"docList\"><div class=\"empty\">Loading documents&hellip;</div></div>\n    </div>\n  </div>\n</div>\n<div class=\"notify\" id=\"notify\"></div>\n<script>\nconst TENANT = 'boxpark';\nfunction showTab(id) {\n  document.querySelectorAll('.nav-item').forEach((t,i) => t.classList.toggle('active', ['dashboard','tickets','conversations','documents','podcast'][i]===id));\n  document.querySelectorAll('.tab-panel').forEach(p => p.classList.toggle('active', p.id==='tab-'+id));\n}\nfunction bar(label,count,max,blue=false) {\n  const pct = max>0 ? Math.round((count/max)*100) : 0;\n  return '<div class=\"bar-row\"><div class=\"bar-label\"><span>'+label+'</span><span>'+count+'</span></div><div class=\"bar-track\"><div class=\"bar-fill'+(blue?' blue':'')+'\" style=\"width:'+pct+'%\"></div></div></div>';\n}\nfunction esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }\nasync function loadAnalytics() {\n  try {\n    const r = await fetch('/boxpark/analytics');\n    const a = await r.json();\n    if (a.error) { console.error(a.error); return; }\n    document.getElementById('sConvs').textContent = a.totalConvs;\n    document.getElementById('sMsgs').textContent = a.totalMessages;\n    document.getElementById('sTickets').textContent = a.openTickets;\n    document.getElementById('sDocs').textContent = a.totalDocs;\n    const tc = document.getElementById('topicsChart');\n    if (!a.topTopics.length) { tc.innerHTML='<div class=\"empty\">No data yet.</div>'; }\n    else { const max=a.topTopics[0][1]; tc.innerHTML=a.topTopics.map(([t,c])=>bar(t,c,max)).join(''); }\n    const vc = document.getElementById('vendorsChart');\n    if (!a.topVendors.length) { vc.innerHTML='<div class=\"empty\">No vendor mentions yet.</div>'; }\n    else { const max=a.topVendors[0][1]; vc.innerHTML=a.topVendors.map(([v,c])=>bar(v.charAt(0).toUpperCase()+v.slice(1),c,max,true)).join(''); }\n    const tt = document.getElementById('ticketsTable');\n    if (!a.tickets.length) { tt.innerHTML='<div class=\"empty\">No tickets yet.</div>'; }\n    else { tt.innerHTML='<table><thead><tr><th>Name</th><th>Unit</th><th>Issue</th><th>Status</th><th>Date</th><th></th></tr></thead><tbody>'+a.tickets.map(t=>'<tr><td><strong>'+esc(t.name||'')+'</strong><br><small>'+esc(t.email||'')+'</small></td><td>'+esc(t.venue||'')+'</td><td class=\"ticket-msg\">'+esc(t.issue||'')+'</td><td><span class=\"badge '+(t.status||'open')+'\">'+esc(t.status||'open')+'</span></td><td>'+new Date(t.created_at).toLocaleDateString('en-GB')+'</td><td>'+(t.status==='open'?'<button class=\"close-btn\" onclick=\"closeTicket('+t.id+')\">Close</button>':'')+'</td></tr>').join('')+'</tbody></table>'; }\n    const ct = document.getElementById('convsTable');\n    if (!a.recentConvs.length) { ct.innerHTML='<div class=\"empty\">No conversations yet.</div>'; }\n    else { ct.innerHTML='<table><thead><tr><th>User</th><th>First message</th><th>Date</th></tr></thead><tbody>'+a.recentConvs.map(c=>{const first=(c.messages||[]).find(m=>m.role==='user');return '<tr><td>'+(c.name?esc(c.name):'Unknown')+'<br><small style=\"color:var(--text-mid)\">'+esc(c.venue||'')+'</small></td><td style=\"max-width:320px\">'+esc((first?.content||'').substring(0,120))+'</td><td>'+new Date(c.created_at).toLocaleDateString('en-GB')+'</td></tr>';}).join('')+'</tbody></table>'; }\n    renderDocs(a.docs);\n  } catch(e) { console.error(e); }\n}\nfunction renderDocs(docs) {\n  const dl = document.getElementById('docList');\n  if (!docs||!docs.length) { dl.innerHTML='<div class=\"empty\">No documents uploaded yet.</div>'; return; }\n  dl.innerHTML = docs.map(function(d) {\n    var fn=esc(d.filename), date=new Date(d.created_at).toLocaleDateString('en-GB'), jsonFn=JSON.stringify(d.filename);\n    return '<div class=\"doc-item\" data-filename=\"'+fn+'\"><div class=\"doc-info\"><div class=\"doc-icon\">&#x1F4C4;</div><div><div class=\"doc-name\">'+fn+'</div><div class=\"doc-date\">Uploaded '+date+'</div></div></div><div class=\"doc-actions\"><span class=\"badge indexed\">Indexed</span><button class=\"btn-delete\" onclick=\"deleteDoc('+jsonFn+', this)\">&#x1F5D1; Delete</button></div></div>';\n  }).join('');\n}\nasync function deleteDoc(filename, btn) {\n  if (!confirm('Delete \"'+filename+'\" from the knowledge base?')) return;\n  btn.disabled=true; btn.textContent='Deleting\\u2026';\n  try {\n    const r = await fetch('/boxpark/documents?filename='+encodeURIComponent(filename), {method:'DELETE'});\n    const d = await r.json();\n    if (d.ok) { notify('\\u2713 '+filename+' deleted','green'); btn.closest('.doc-item').remove(); setTimeout(loadAnalytics,500); }\n    else { notify('Delete failed \\u2014 check Render logs','red'); btn.disabled=false; btn.textContent='\\u1F5D1 Delete'; }\n  } catch(e) { notify('Delete failed: '+e.message,'red'); btn.disabled=false; btn.textContent='\\u1F5D1 Delete'; }\n}\nasync function closeTicket(id) {\n  await fetch('/boxpark/ticket/'+id+'/close', {method:'POST'});\n  notify('Ticket closed','green'); loadAnalytics();\n}\nfunction dragOver(e){e.preventDefault();document.getElementById('dropZone').classList.add('dragging');}\nfunction dragLeave(){document.getElementById('dropZone').classList.remove('dragging');}\nfunction dropFiles(e){e.preventDefault();document.getElementById('dropZone').classList.remove('dragging');handleFiles(e.dataTransfer.files);}\nasync function handleFiles(files) {\n  for (const file of files) {\n    const item = document.createElement('div'); item.className='upload-item';\n    item.innerHTML='<div><div class=\"fname\">'+esc(file.name)+'</div><div class=\"fsize\">'+(file.size/1024).toFixed(0)+' KB</div><div class=\"progress\"><div class=\"progress-bar\" id=\"pb_'+file.name.replace(/\\W/g,'')+'\"></div></div></div><span>\\u23f3</span>';\n    document.getElementById('uploadList').appendChild(item);\n    try {\n      const text = await new Promise((res,rej)=>{const r=new FileReader();r.onload=e=>res(e.target.result);r.onerror=rej;r.readAsText(file);});\n      const pb = document.getElementById('pb_'+file.name.replace(/\\W/g,''));\n      if(pb) pb.style.width='50%';\n      const r = await fetch('/boxpark/upload', {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({filename:file.name, content:text})});\n      await r.json();\n      if(pb) pb.style.width='100%';\n      item.querySelector('span').textContent='\\u2705';\n      notify(file.name+' indexed!','green');\n      setTimeout(loadAnalytics,1000);\n    } catch(e) { item.querySelector('span').textContent='\\u274c'; notify('Failed: '+file.name,'red'); }\n  }\n}\nfunction notify(msg, type='') {\n  const n = document.getElementById('notify');\n  n.textContent=msg; n.className='notify '+type+' show';\n  setTimeout(()=>n.className='notify', 3500);\n}\nloadAnalytics();\n</script>\n</body>\n</html>";
const STACKED_CHAT = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no, viewport-fit=cover\">\n<title>Stacked Chat</title>\n<link rel=\"icon\" type=\"image/png\" href=\"data:image/svg+xml;base64,\">\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js\"></script>\n<link href=\"https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,600;9..144,700&family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600;9..40,900&family=Baumans&family=Righteous&display=swap\" rel=\"stylesheet\">\n<style>\n  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n  :root {\n    --cream: #eef4fb;\n    --cream-dark: #d4e6f7;\n    --orange: #0F9BFF;\n    --orange-light: #3db0ff;\n    --brown: #0d2540;\n    --brown-mid: #3a6080;\n    --white: #ffffff;\n    --green: #2a9d5c;\n    --red: #d64545;\n    --shadow: 0 2px 16px rgba(15,155,255,0.10);\n    --shadow-lg: 0 8px 32px rgba(15,155,255,0.15);\n  }\n\n  html {\n    height: 100%; height: 100dvh;\n    overflow-x: hidden;\n    overflow-y: hidden;\n  }\n\n  body {\n    height: 100%; height: 100dvh;\n    background: var(--cream);\n    font-family: 'DM Sans', sans-serif;\n    color: var(--brown);\n    overflow: hidden;\n    overscroll-behavior: none;\n    touch-action: pan-y;\n    max-width: 100vw;\n  }\n\n  /* \u2500\u2500\u2500 GATE \u2500\u2500\u2500 */\n  #gate {\n    position: fixed; inset: 0;\n    background: var(--cream);\n    display: flex; align-items: center; justify-content: center;\n    z-index: 100;\n    padding: 24px;\n  }\n  #gate.hidden { display: none; }\n\n  .gate-card {\n    background: var(--white);\n    border-radius: 24px;\n    padding: 40px 32px;\n    width: 100%; max-width: 420px;\n    box-shadow: var(--shadow-lg);\n    text-align: center;\n  }\n  .gate-logo { height: 44px; max-width: 240px; object-fit: contain; margin-bottom: 4px; }\n  .gate-sub {\n    font-size: 13px; color: var(--brown-mid); margin-bottom: 28px;\n    font-weight: 400; letter-spacing: 0.02em;\n  }\n  .gate-card h2 {\n    font-family: 'Fraunces', serif;\n    font-size: 22px; font-weight: 700; margin-bottom: 6px;\n  }\n  .gate-card p { font-size: 14px; color: var(--brown-mid); margin-bottom: 24px; line-height: 1.5; }\n\n  .gate-input {\n    width: 100%; padding: 13px 16px;\n    border: 1.5px solid var(--cream-dark);\n    border-radius: 12px;\n    font-family: 'DM Sans', sans-serif;\n    font-size: 15px; color: var(--brown);\n    background: var(--cream);\n    margin-bottom: 12px;\n    outline: none;\n    transition: border-color 0.2s;\n  }\n  .gate-input:focus { border-color: var(--orange); background: var(--white); }\n  .gate-input::placeholder { color: var(--brown-mid); opacity: 0.6; }\n\n  .gate-btn {\n    width: 100%; padding: 14px;\n    background: var(--orange); color: #fff;\n    border: none; border-radius: 12px;\n    font-family: 'DM Sans', sans-serif; font-size: 16px; font-weight: 600;\n    cursor: pointer; margin-top: 4px;\n    transition: background 0.2s, transform 0.1s;\n  }\n  .gate-btn:hover { background: var(--orange-light); }\n  .gate-btn:active { transform: scale(0.98); }\n\n  .gate-error {\n    font-size: 13px; color: var(--red);\n    margin-top: -6px; margin-bottom: 8px; display: none;\n  }\n\n  /* \u2500\u2500\u2500 APP SHELL \u2500\u2500\u2500 */\n  #app {\n    display: flex; flex-direction: column;\n    height: 100%; height: 100dvh;\n    width: 100%; max-width: 100vw;\n    overflow: hidden;\n  }\n\n  /* \u2500\u2500\u2500 HEADER \u2500\u2500\u2500 */\n  header {\n    display: flex; align-items: center; justify-content: space-between;\n    padding: 14px 20px;\n    background: var(--white);\n    border-bottom: 1px solid var(--cream-dark);\n    flex-shrink: 0;\n    box-shadow: 0 1px 8px rgba(15,155,255,0.06);\n    width: 100%; max-width: 100vw;\n    overflow: hidden;\n  }\n  .header-logo { height: 28px; max-width: 180px; object-fit: contain; }\n  .header-actions { display: flex; gap: 8px; align-items: center; }\n\n  .icon-btn {\n    background: none; border: none; cursor: pointer;\n    padding: 8px; border-radius: 10px; color: var(--brown-mid);\n    font-size: 18px; transition: background 0.15s, color 0.15s;\n    display: flex; align-items: center; justify-content: center;\n  }\n  .icon-btn:hover { background: var(--cream); color: var(--brown); }\n\n  .user-chip {\n    display: flex; align-items: center; gap: 8px;\n    background: var(--cream); border-radius: 20px; padding: 6px 12px 6px 8px;\n    font-size: 13px; font-weight: 500; color: var(--brown);\n  }\n  .user-chip .dot {\n    width: 8px; height: 8px; border-radius: 50%; background: var(--green);\n  }\n\n  /* \u2500\u2500\u2500 MAIN CHAT \u2500\u2500\u2500 */\n  main {\n    flex: 1; overflow: hidden;\n    display: flex; flex-direction: column;\n    min-height: 0;\n  }\n\n  #messages {\n    flex: 1; overflow-y: auto; overflow-x: hidden;\n    padding: 20px 16px 8px;\n    display: flex; flex-direction: column; gap: 16px;\n    scroll-behavior: smooth;\n    width: 100%;\n  }\n\n  /* welcome */\n  .welcome {\n    display: flex; flex-direction: column; align-items: center;\n    justify-content: center; flex: 1; padding: 32px 16px; gap: 12px;\n    text-align: center;\n  }\n  .welcome-wordmark { height: 52px; margin-bottom: 0px; max-width: 320px; object-fit: contain; }\n  .welcome h2 {\n    font-family: 'Fraunces', serif;\n    font-size: 24px; font-weight: 700; line-height: 1.2;\n  }\n  .welcome p { font-size: 14px; color: var(--brown-mid); margin-bottom: 8px; }\n\n  .quick-grid {\n    display: grid; grid-template-columns: 1fr 1fr;\n    gap: 12px; width: 100%; max-width: 380px;\n  }\n  .quick-btn {\n    background: var(--white); border: 2px solid var(--cream-dark);\n    border-radius: 16px; padding: 18px 14px;\n    font-family: 'DM Sans', sans-serif; font-size: 14px; font-weight: 700;\n    color: var(--brown); cursor: pointer; text-align: left;\n    transition: border-color 0.2s, box-shadow 0.2s, transform 0.1s;\n    line-height: 1.25; min-height: 90px;\n    display: flex; flex-direction: column; justify-content: flex-end;\n  }\n  .quick-btn:hover { border-color: var(--orange); box-shadow: 0 4px 16px rgba(15,155,255,0.15); transform: translateY(-1px); }\n  .quick-btn:active { transform: scale(0.97); }\n  .quick-btn .emoji { font-size: 24px; display: block; margin-bottom: 8px; }\n\n  /* messages */\n  .msg { display: flex; align-items: flex-start; gap: 10px; max-width: 100%; }\n  .msg.user { flex-direction: row-reverse; }\n\n  .msg-avatar {\n    width: 32px; height: 32px; border-radius: 50%; flex-shrink: 0;\n    background: var(--cream-dark);\n    display: flex; align-items: center; justify-content: center;\n    font-size: 13px; font-weight: 600; color: var(--brown);\n    overflow: hidden;\n  }\n  .msg-avatar img { width: 100%; height: 100%; object-fit: contain; }\n\n  .msg-bubble {\n    background: var(--white); border-radius: 18px 18px 18px 4px;\n    padding: 12px 16px; font-size: 15px; line-height: 1.55;\n    max-width: min(calc(100vw - 90px), 520px);\n    box-shadow: var(--shadow);\n    white-space: pre-wrap;\n    word-wrap: break-word;\n    overflow-wrap: break-word;\n  }\n  .msg-bubble a { color: var(--orange); font-weight: 600; text-decoration: underline; }\n  .msg-bubble strong { font-weight: 700; }\n  .msg.user .msg-bubble {\n    background: var(--orange); color: #fff;\n    border-radius: 18px 18px 4px 18px;\n    box-shadow: 0 2px 12px rgba(15,155,255,0.25);\n  }\n\n  /* ticket button */\n  .ticket-row {\n    display: flex; justify-content: center; margin-top: -4px;\n  }\n  .ticket-btn {\n    background: var(--white); border: 1.5px solid var(--cream-dark);\n    border-radius: 20px; padding: 8px 16px;\n    font-family: 'DM Sans', sans-serif; font-size: 13px; font-weight: 500;\n    color: var(--brown-mid); cursor: pointer;\n    display: flex; align-items: center; gap: 6px;\n    transition: border-color 0.2s, color 0.2s;\n  }\n  .ticket-btn:hover { border-color: var(--orange); color: var(--orange); }\n  .link-row { display: flex; flex-wrap: wrap; gap: 8px; margin-top: -4px; padding-left: 42px; }\n  .link-pill { display: inline-flex; align-items: center; gap: 6px; background: var(--orange); border: none; border-radius: 20px; padding: 8px 14px; font-size: 13px; font-weight: 600; color: #fff; text-decoration: none; transition: all 0.15s; white-space: nowrap; box-shadow: 0 2px 8px rgba(15,155,255,0.25); }\n  .link-pill:hover { background: #0d7acc; transform: translateY(-1px); box-shadow: 0 4px 12px rgba(15,155,255,0.35); }\n\n  /* typing */\n  .typing-bubble {\n    display: flex; align-items: flex-start; gap: 10px;\n  }\n  .dots {\n    display: flex; gap: 4px; align-items: center;\n    background: var(--white); border-radius: 18px; padding: 12px 16px;\n    box-shadow: var(--shadow);\n  }\n  .dot-anim {\n    width: 8px; height: 8px; border-radius: 50%; background: var(--brown-mid);\n    animation: bounce 1.2s infinite;\n  }\n  .dot-anim:nth-child(2) { animation-delay: 0.2s; }\n  .dot-anim:nth-child(3) { animation-delay: 0.4s; }\n  @keyframes bounce {\n    0%, 60%, 100% { transform: translateY(0); }\n    30% { transform: translateY(-6px); }\n  }\n\n  /* \u2500\u2500\u2500 INPUT BAR \u2500\u2500\u2500 */\n  .input-bar {\n    padding: 10px 12px;\n    padding-bottom: calc(10px + env(safe-area-inset-bottom));\n    background: var(--white);\n    border-top: 1px solid var(--cream-dark);\n    flex-shrink: 0;\n    display: flex; gap: 8px; align-items: flex-end;\n    min-width: 0;\n  }\n  #input {\n    flex: 1; min-width: 0; padding: 11px 14px;\n    background: var(--cream); border: 1.5px solid var(--cream-dark);\n    border-radius: 20px; font-family: 'DM Sans', sans-serif; font-size: 15px;\n    color: var(--brown); resize: none; outline: none;\n    max-height: 120px; line-height: 1.4;\n    transition: border-color 0.2s;\n  }\n  #input:focus { border-color: var(--orange); background: #fff; }\n  #input::placeholder { color: var(--brown-mid); opacity: 0.6; }\n\n  #mic {\n    width: 44px; height: 44px; border-radius: 50%;\n    background: var(--cream); border: 1.5px solid var(--cream-dark); cursor: pointer;\n    display: flex; align-items: center; justify-content: center;\n    flex-shrink: 0; transition: all 0.15s; color: var(--brown-mid);\n  }\n  #mic:hover { border-color: var(--orange); color: var(--orange); }\n  #mic.listening { background: var(--orange); border-color: var(--orange); color: #fff; animation: pulse 1s infinite; }\n  @keyframes pulse { 0%,100% { box-shadow: 0 0 0 0 rgba(15,155,255,0.4); } 50% { box-shadow: 0 0 0 8px rgba(15,155,255,0); } }\n\n  #send {\n    width: 44px; height: 44px; border-radius: 50%;\n    background: var(--orange); border: none; cursor: pointer;\n    display: flex; align-items: center; justify-content: center;\n    flex-shrink: 0; transition: background 0.15s, transform 0.1s;\n    box-shadow: 0 2px 12px rgba(15,155,255,0.35);\n  }\n  #send:hover { background: var(--orange-light); }\n  #send:active { transform: scale(0.93); }\n  #send svg { width: 18px; height: 18px; fill: #fff; }\n  #send:disabled { opacity: 0.5; cursor: default; }\n\n  /* \u2500\u2500\u2500 HISTORY DRAWER \u2500\u2500\u2500 */\n  .drawer-overlay {\n    position: fixed; inset: 0; background: rgba(13,37,64,0.4);\n    z-index: 50; opacity: 0; pointer-events: none;\n    transition: opacity 0.25s;\n  }\n  .drawer-overlay.open { opacity: 1; pointer-events: all; }\n\n  .drawer {\n    position: fixed; bottom: 0; left: 0; right: 0;\n    background: var(--white); border-radius: 24px 24px 0 0;\n    z-index: 51; max-height: 70vh;\n    transform: translateY(100%); transition: transform 0.3s cubic-bezier(0.32,0.72,0,1);\n    display: flex; flex-direction: column;\n    padding-bottom: env(safe-area-inset-bottom);\n  }\n  .drawer.open { transform: translateY(0); }\n\n  .drawer-handle {\n    width: 40px; height: 4px; background: var(--cream-dark);\n    border-radius: 2px; margin: 12px auto 0;\n  }\n  .drawer-header {\n    padding: 16px 20px 12px;\n    font-family: 'Fraunces', serif;\n    font-size: 18px; font-weight: 700;\n    border-bottom: 1px solid var(--cream-dark);\n    display: flex; align-items: center; justify-content: space-between;\n  }\n  .drawer-close {\n    background: none; border: none; font-size: 20px;\n    cursor: pointer; color: var(--brown-mid); padding: 4px;\n  }\n  .drawer-body { overflow-y: auto; padding: 16px 20px; flex: 1; }\n\n  .history-item {\n    padding: 14px 0; border-bottom: 1px solid var(--cream-dark);\n    cursor: pointer;\n  }\n  .history-item:last-child { border-bottom: none; }\n  .history-item:hover .history-preview { color: var(--orange); }\n  .history-date { font-size: 11px; color: var(--brown-mid); margin-bottom: 4px; }\n  .history-preview { font-size: 14px; font-weight: 500; color: var(--brown); transition: color 0.15s; }\n  .history-count { font-size: 12px; color: var(--brown-mid); margin-top: 2px; }\n\n  .empty-history {\n    text-align: center; padding: 32px 0;\n    color: var(--brown-mid); font-size: 14px;\n  }\n\n  /* \u2500\u2500\u2500 TOPICS DRAWER \u2500\u2500\u2500 */\n  .topics-list { display: flex; flex-direction: column; gap: 8px; }\n  .topic-chip {\n    background: var(--cream); border: 1.5px solid var(--cream-dark);\n    border-radius: 12px; padding: 12px 16px;\n    font-size: 14px; font-weight: 500; color: var(--brown);\n    cursor: pointer; text-align: left;\n    display: flex; align-items: center; gap: 10px;\n    transition: border-color 0.15s;\n  }\n  .topic-chip:hover { border-color: var(--orange); }\n\n  /* \u2500\u2500\u2500 TICKET MODAL \u2500\u2500\u2500 */\n  .modal-overlay {\n    position: fixed; inset: 0; background: rgba(13,37,64,0.5);\n    z-index: 200; display: flex; align-items: flex-end;\n    opacity: 0; pointer-events: none; transition: opacity 0.2s;\n  }\n  .modal-overlay.open { opacity: 1; pointer-events: all; }\n\n  .modal {\n    background: var(--white); border-radius: 24px 24px 0 0;\n    padding: 24px 24px calc(24px + env(safe-area-inset-bottom));\n    width: 100%;\n    transform: translateY(100%); transition: transform 0.3s cubic-bezier(0.32,0.72,0,1);\n  }\n  .modal-overlay.open .modal { transform: translateY(0); }\n\n  .modal h3 {\n    font-family: 'Fraunces', serif;\n    font-size: 20px; margin-bottom: 6px;\n  }\n  .modal p { font-size: 14px; color: var(--brown-mid); margin-bottom: 20px; }\n  .modal textarea {\n    width: 100%; border: 1.5px solid var(--cream-dark);\n    border-radius: 12px; padding: 12px 14px;\n    font-family: 'DM Sans', sans-serif; font-size: 14px; color: var(--brown);\n    background: var(--cream); resize: none; height: 100px;\n    outline: none; margin-bottom: 14px;\n    transition: border-color 0.2s;\n  }\n  .modal textarea:focus { border-color: var(--orange); background: #fff; }\n  .modal-actions { display: flex; gap: 10px; }\n  .modal-cancel {\n    flex: 1; padding: 13px; background: var(--cream); border: none;\n    border-radius: 12px; font-family: 'DM Sans', sans-serif;\n    font-size: 15px; font-weight: 500; cursor: pointer; color: var(--brown);\n  }\n  .modal-submit {\n    flex: 2; padding: 13px; background: var(--orange); border: none;\n    border-radius: 12px; font-family: 'DM Sans', sans-serif;\n    font-size: 15px; font-weight: 600; cursor: pointer; color: #fff;\n    transition: background 0.15s;\n  }\n  .modal-submit:hover { background: var(--orange-light); }\n\n  /* \u2500\u2500\u2500 TOAST \u2500\u2500\u2500 */\n  .toast {\n    position: fixed; bottom: calc(80px + env(safe-area-inset-bottom));\n    left: 50%; transform: translateX(-50%) translateY(20px);\n    background: var(--brown); color: #fff;\n    border-radius: 20px; padding: 10px 20px;\n    font-size: 14px; font-weight: 500;\n    opacity: 0; transition: all 0.3s; z-index: 300; white-space: nowrap;\n  }\n  .toast.show { opacity: 1; transform: translateX(-50%) translateY(0); }\n  .toast.green { background: var(--green); }\n\n\n  /* \u2500\u2500\u2500 SOCIAL PROOF \u2500\u2500\u2500 */\n  .social-proof {\n    display: flex; align-items: center; gap: 6px;\n    background: var(--white); border-radius: 20px;\n    padding: 6px 14px; font-size: 12px; font-weight: 600;\n    color: var(--brown-mid); box-shadow: var(--shadow);\n    margin-bottom: 4px;\n  }\n  .social-proof .pulse {\n    width: 7px; height: 7px; border-radius: 50%;\n    background: var(--green); flex-shrink: 0;\n    animation: pulse-green 2s infinite;\n  }\n  @keyframes pulse-green {\n    0%,100% { box-shadow: 0 0 0 0 rgba(42,157,92,0.4); }\n    50% { box-shadow: 0 0 0 5px rgba(42,157,92,0); }\n  }\n\n  /* \u2500\u2500\u2500 PREDICTIVE FIXES \u2500\u2500\u2500 */\n  .predict-section {\n    width: 100%; max-width: 380px; margin-top: 4px;\n  }\n  .predict-label {\n    font-size: 11px; font-weight: 600; letter-spacing: 0.08em;\n    text-transform: uppercase; color: var(--brown-mid);\n    opacity: 0.6; margin-bottom: 8px; text-align: left;\n    padding-left: 2px;\n  }\n  .predict-grid {\n    display: flex; flex-direction: column; gap: 8px;\n  }\n  .predict-btn {\n    background: var(--white); border: 1.5px solid var(--cream-dark);\n    border-radius: 12px; padding: 10px 14px;\n    font-family: 'DM Sans', sans-serif; font-size: 13px; font-weight: 600;\n    color: var(--brown); cursor: pointer; text-align: left;\n    display: flex; align-items: center; gap: 10px;\n    transition: border-color 0.2s, box-shadow 0.2s;\n    width: 100%;\n  }\n  .predict-btn:hover { border-color: var(--orange); box-shadow: 0 2px 12px rgba(15,155,255,0.12); }\n  .predict-btn .predict-icon { font-size: 16px; flex-shrink: 0; }\n  .predict-tag {\n    margin-left: auto; font-size: 10px; font-weight: 700;\n    letter-spacing: 0.06em; text-transform: uppercase;\n    background: var(--orange); color: #fff;\n    border-radius: 8px; padding: 2px 7px; flex-shrink: 0;\n  }\n\n  /* \u2500\u2500\u2500 QR CODE \u2500\u2500\u2500 */\n  .qr-section {\n    margin-top: 8px; display: flex; flex-direction: column;\n    align-items: center; gap: 6px;\n  }\n  .qr-box {\n    background: var(--white); border-radius: 16px;\n    padding: 12px; box-shadow: var(--shadow);\n    cursor: pointer;\n  }\n  .qr-box canvas, .qr-box img { display: block; border-radius: 4px; }\n  .qr-label {\n    font-size: 11px; color: var(--brown-mid); font-weight: 500;\n    text-align: center; opacity: 0.7;\n  }\n  /* scrollbar */\n  #messages::-webkit-scrollbar { width: 4px; }\n  #messages::-webkit-scrollbar-track { background: transparent; }\n  #messages::-webkit-scrollbar-thumb { background: var(--cream-dark); border-radius: 2px; }\n\n  /* \u2500\u2500\u2500 LOGO SCROLL STRIP \u2500\u2500\u2500 */\n  .logo-strip {\n    flex-shrink: 0;\n    overflow: hidden;\n    background: var(--white);\n    border-bottom: 1px solid var(--cream-dark);\n    padding: 12px 0;\n    position: relative;\n  }\n  .logo-strip::before,\n  .logo-strip::after {\n    content: '';\n    position: absolute; top: 0; bottom: 0; width: 48px; z-index: 2;\n    pointer-events: none;\n  }\n  .logo-strip::before { left: 0; background: linear-gradient(to right, var(--white), transparent); }\n  .logo-strip::after  { right: 0; background: linear-gradient(to left, var(--white), transparent); }\n\n  .logo-track {\n    display: flex; align-items: center; gap: 44px;\n    width: max-content;\n    animation: logoScroll 30s linear infinite;\n  }\n  .logo-track:hover { animation-play-state: paused; }\n\n  .logo-item {\n    height: 26px; width: auto;\n    max-width: 100px;\n    object-fit: contain;\n    opacity: 0.35;\n    filter: grayscale(100%);\n    flex-shrink: 0;\n  }\n\n  .logo-text {\n    font-family: 'DM Sans', sans-serif;\n    font-size: 12px;\n    font-weight: 800;\n    letter-spacing: 0.04em;\n    text-transform: uppercase;\n    color: var(--brown-dark);\n    opacity: 0.3;\n    white-space: nowrap;\n    flex-shrink: 0;\n    user-select: none;\n  }\n\n  /* separator dot between partners */\n  .logo-dot {\n    width: 4px; height: 4px;\n    background: var(--brown-dark);\n    border-radius: 50%;\n    opacity: 0.15;\n    flex-shrink: 0;\n  }\n\n  .strip-label {\n    font-size: 10px; font-weight: 600; letter-spacing: 0.1em;\n    text-transform: uppercase; color: var(--brown-mid);\n    opacity: 0.45; white-space: nowrap; flex-shrink: 0;\n  }\n\n  @keyframes logoScroll {\n    0%   { transform: translateX(0); }\n    100% { transform: translateX(-50%); }\n  }\n</style>\n</head>\n<body>\n\n<!-- \u2500\u2500\u2500 GATE \u2500\u2500\u2500 -->\n<div id=\"gate\">\n  <div class=\"gate-card\">\n    <img class=\"gate-logo\" id=\"gateWordmark\" src=\"data:image/svg+xml;base64,\" alt=\"Stacked\">\n    <p class=\"gate-sub\">Hospitality tech support, powered by AI</p>\n    <h2>Welcome \u2014 let's get you sorted</h2>\n    <p>Drop your details below and we'll have you chatting in seconds.</p>\n    <input class=\"gate-input\" type=\"text\" id=\"gateName\" placeholder=\"Your name\" autocomplete=\"given-name\">\n    <input class=\"gate-input\" type=\"text\" id=\"gateVenue\" placeholder=\"Venue / group name\" autocomplete=\"organization\">\n    <input class=\"gate-input\" type=\"tel\" id=\"gatePhone\" placeholder=\"Phone number\" autocomplete=\"tel\">\n    <input class=\"gate-input\" type=\"email\" id=\"gateEmail\" placeholder=\"Email address\" autocomplete=\"email\">\n    <div class=\"gate-error\" id=\"gateError\">Please fill in all fields with a valid email.</div>\n    <button class=\"gate-btn\" onclick=\"submitGate()\">Start chatting \u2192</button>\n  </div>\n</div>\n\n<!-- \u2500\u2500\u2500 APP \u2500\u2500\u2500 -->\n<div id=\"app\">\n  <header>\n    <a href=\"https://wearestacked.io\" target=\"_blank\" rel=\"noopener\" style=\"display:flex;flex-direction:column;align-items:flex-start;text-decoration:none;gap:2px;\">\n      <img class=\"header-logo\" id=\"headerIcon\" src=\"data:image/svg+xml;base64,\" alt=\"Stacked\">\n      <span style=\"font-family:'Righteous',sans-serif;font-size:12px;letter-spacing:0.04em;text-transform:uppercase;color:var(--orange);padding-left:1px;margin-top:2px;\">CHAT</span>\n    </a>\n    <div class=\"header-actions\">\n      <div class=\"user-chip\">\n        <div class=\"dot\"></div>\n        <span id=\"userLabel\">You</span>\n      </div>\n      <button class=\"icon-btn\" onclick=\"openHistory()\" title=\"Chat history\">\n        <svg viewBox=\"0 0 24 24\" width=\"20\" height=\"20\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\">\n          <path d=\"M12 8v4l3 3M12 2a10 10 0 1 0 0 20A10 10 0 0 0 12 2z\"/>\n        </svg>\n      </button>\n      <button class=\"icon-btn\" onclick=\"openTopics()\" title=\"Topics\">\n        <svg viewBox=\"0 0 24 24\" width=\"20\" height=\"20\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\">\n          <line x1=\"3\" y1=\"12\" x2=\"21\" y2=\"12\"/><line x1=\"3\" y1=\"6\" x2=\"21\" y2=\"6\"/><line x1=\"3\" y1=\"18\" x2=\"21\" y2=\"18\"/>\n        </svg>\n      </button>\n    </div>\n  </header>\n\n  <!-- \u2500\u2500\u2500 LOGO STRIP \u2500\u2500\u2500 -->\n  <div class=\"logo-strip\">\n    <div class=\"logo-track\">\n      <span class=\"logo-text\">Lightspeed</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Square</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Fourth</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Sky Business</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Deputy</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">OpenTable</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Deliverect</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Bizimply</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Tevalis</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Tenzo</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Airship</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Planday</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Workforce</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Crunchtime</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Nory</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Sona</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Stampede</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Openr</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Apicbase</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Giftpro</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"strip-label\">+ 80 more partners</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Lightspeed</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Square</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Fourth</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Sky Business</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Deputy</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">OpenTable</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Deliverect</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Bizimply</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Tevalis</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Tenzo</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Airship</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Planday</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Workforce</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Crunchtime</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Nory</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Sona</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Stampede</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Openr</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Apicbase</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"logo-text\">Giftpro</span>\n      <span class=\"logo-dot\"></span>\n      <span class=\"strip-label\">+ 80 more partners</span>\n      <span class=\"logo-dot\"></span>\n    </div>\n  </div>\n\n  <main>\n    <div id=\"messages\">\n      <div class=\"welcome\" id=\"welcome\">\n        <img class=\"welcome-wordmark\" id=\"welcomeWordmark\" src=\"data:image/svg+xml;base64,\" alt=\"Stacked\">\n        <div style=\"font-family:'Righteous',sans-serif;font-size:22px;letter-spacing:0.05em;text-transform:uppercase;color:var(--orange);margin-top:2px;margin-bottom:8px;\">CHAT</div>\n        <div class=\"social-proof\"><div class=\"pulse\"></div><span id=\"socialProofText\">Loading\u2026</span></div>\n        <h2>Got a tech problem?<br>Let's fix it.</h2>\n        <p id=\"welcomeVenue\">Ask anything about your hospitality tech.</p>\n        <div class=\"predict-section\" id=\"predictSection\" style=\"display:none\">\n          <div class=\"predict-label\" id=\"predictLabel\">Trending right now</div>\n          <div class=\"predict-grid\" id=\"predictGrid\"></div>\n        </div>\n        <div class=\"quick-grid\" id=\"quickGrid\" style=\"margin-top:8px;\"></div>\n        <div class=\"qr-section\" id=\"qrSection\">\n          <div class=\"qr-box\" id=\"qrCode\" title=\"Share this with your team\"></div>\n          <div class=\"qr-label\">Share with your team \u2014 scan to open</div>\n        </div>\n      </div>\n    </div>\n  </main>\n\n  <div class=\"input-bar\">\n    <textarea id=\"input\" placeholder=\"Describe your tech issue\u2026\" rows=\"1\" onkeydown=\"handleKey(event)\" oninput=\"autoResize(this)\"></textarea>\n    <button id=\"mic\" onclick=\"toggleMic()\" title=\"Voice input\">\n      <svg viewBox=\"0 0 24 24\" width=\"20\" height=\"20\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"9\" y=\"2\" width=\"6\" height=\"11\" rx=\"3\"/><path d=\"M5 10a7 7 0 0 0 14 0M12 19v3M8 22h8\"/></svg>\n    </button>\n    <button id=\"send\" onclick=\"sendMessage()\" title=\"Send\">\n      <svg viewBox=\"0 0 24 24\"><path d=\"M2 21l21-9L2 3v7l15 2-15 2z\"/></svg>\n    </button>\n  </div>\n</div>\n\n<!-- \u2500\u2500\u2500 HISTORY DRAWER \u2500\u2500\u2500 -->\n<div class=\"drawer-overlay\" id=\"histOverlay\" onclick=\"closeHistory()\"></div>\n<div class=\"drawer\" id=\"histDrawer\">\n  <div class=\"drawer-handle\"></div>\n  <div class=\"drawer-header\">\n    <span>Chat history</span>\n    <button class=\"drawer-close\" onclick=\"closeHistory()\">\u2715</button>\n  </div>\n  <div class=\"drawer-body\" id=\"histBody\">\n    <div class=\"empty-history\">No previous chats yet.</div>\n  </div>\n</div>\n\n<!-- \u2500\u2500\u2500 TOPICS DRAWER \u2500\u2500\u2500 -->\n<div class=\"drawer-overlay\" id=\"topicOverlay\" onclick=\"closeTopics()\"></div>\n<div class=\"drawer\" id=\"topicDrawer\">\n  <div class=\"drawer-handle\"></div>\n  <div class=\"drawer-header\">\n    <span>Common topics</span>\n    <button class=\"drawer-close\" onclick=\"closeTopics()\">\u2715</button>\n  </div>\n  <div class=\"drawer-body\">\n    <div class=\"topics-list\">\n      <button class=\"topic-chip\" onclick=\"quickSend('EPOS system frozen or crashed'); closeTopics()\">\ud83d\udcbb EPOS frozen or crashed</button>\n      <button class=\"topic-chip\" onclick=\"quickSend('Payment terminal offline or not processing'); closeTopics()\">\ud83d\udcb3 Payment terminal issues</button>\n      <button class=\"topic-chip\" onclick=\"quickSend('WiFi or network connectivity problem'); closeTopics()\">\ud83d\udcf6 WiFi / network down</button>\n      <button class=\"topic-chip\" onclick=\"quickSend('Kitchen printer not printing or offline'); closeTopics()\">\ud83d\udda8\ufe0f Kitchen printer offline</button>\n      <button class=\"topic-chip\" onclick=\"quickSend('Contactless payments not working'); closeTopics()\">\ud83d\udcf1 Contactless not working</button>\n      <button class=\"topic-chip\" onclick=\"quickSend('EPOS running slowly or lagging'); closeTopics()\">\ud83d\udc0c EPOS slow or lagging</button>\n      <button class=\"topic-chip\" onclick=\"quickSend('Staff cannot log in to the system'); closeTopics()\">\ud83d\udd12 Login / access issues</button>\n      <button class=\"topic-chip\" onclick=\"quickSend('Card reader not connecting to EPOS'); closeTopics()\">\ud83d\udd17 Card reader not connecting</button>\n    </div>\n  </div>\n</div>\n\n<!-- \u2500\u2500\u2500 TICKET MODAL \u2500\u2500\u2500 -->\n<div class=\"modal-overlay\" id=\"ticketOverlay\">\n  <div class=\"modal\">\n    <h3>Raise a support ticket</h3>\n    <p>We'll look into this and get back to you. Add any extra detail below.</p>\n    <textarea id=\"ticketNote\" placeholder=\"Any extra context that might help\u2026\"></textarea>\n    <div class=\"modal-actions\">\n      <button class=\"modal-cancel\" onclick=\"closeTicket()\">Cancel</button>\n      <button class=\"modal-submit\" onclick=\"submitTicket()\">Submit ticket</button>\n    </div>\n  </div>\n</div>\n\n<!-- \u2500\u2500\u2500 TOAST \u2500\u2500\u2500 -->\n<div class=\"toast\" id=\"toast\"></div>\n\n<script>\n// \u2500\u2500\u2500 CONFIG \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst SERVER_URL = 'https://toast-support-bot.onrender.com';\nconst SUPABASE_URL = 'https://yuzlfocqovwhqdpitvxj.supabase.co';\nconst SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inl1emxmb2Nxb3Z3aHFkcGl0dnhqIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzIyODE3OTgsImV4cCI6MjA4Nzg1Nzc5OH0.zN_GOXI8MI9isqnVRCZvxAmU1ZyXIfWvq-P3SkSh4Vk';\n\n// Brand assets from GitHub\nconst ICON_URL = 'data:image/svg+xml;base64,';\nconst WORDMARK_URL = 'data:image/svg+xml;base64,';\n\n// \u2500\u2500\u2500 STATE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlet user = null;\nlet messages = []; // {role, content}\nlet conversationId = null;\nlet lastBotMsg = '';\n\n// \u2500\u2500\u2500 INIT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nwindow.addEventListener('DOMContentLoaded', () => {\n  renderQuickBtns();\n  loadSocialProof();\n  loadPredictiveFixes();\n  renderQRCode();\n  const saved = localStorage.getItem('stacked_user');\n  if (saved) {\n    user = JSON.parse(saved);\n    showApp();\n  }\n});\n\n// \u2500\u2500\u2500 GATE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function submitGate() {\n  const name = document.getElementById('gateName').value.trim();\n  const venue = document.getElementById('gateVenue').value.trim();\n  const phone = document.getElementById('gatePhone').value.trim();\n  const email = document.getElementById('gateEmail').value.trim();\n  const err = document.getElementById('gateError');\n\n  if (!name || !venue || !email || !/\\S+@\\S+\\.\\S+/.test(email)) {\n    err.style.display = 'block'; return;\n  }\n  err.style.display = 'none';\n\n  user = { name, venue, phone, email };\n  localStorage.setItem('stacked_user', JSON.stringify(user));\n\n  // Save lead to server\n  try {\n    await fetch(`${SERVER_URL}/save-lead`, {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ name, venue, phone, email })\n    });\n  } catch(e) { /* fail silently */ }\n\n  showApp();\n}\n\nfunction showApp() {\n  document.getElementById('gate').classList.add('hidden');\n  document.getElementById('userLabel').textContent = user.name.split(' ')[0];\n  personaliseWelcome();\n  loadHistory();\n}\n\n// \u2500\u2500\u2500 SUPABASE HELPERS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function supabaseInsert(table, data) {\n  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {\n    method: 'POST',\n    headers: {\n      'Content-Type': 'application/json',\n      'apikey': SUPABASE_KEY,\n      'Authorization': `Bearer ${SUPABASE_KEY}`,\n      'Prefer': 'return=representation'\n    },\n    body: JSON.stringify(data)\n  });\n  return r.json();\n}\n\nasync function supabaseUpsert(table, data, onConflict) {\n  const url = `${SUPABASE_URL}/rest/v1/${table}?on_conflict=${onConflict}`;\n  const r = await fetch(url, {\n    method: 'POST',\n    headers: {\n      'Content-Type': 'application/json',\n      'apikey': SUPABASE_KEY,\n      'Authorization': `Bearer ${SUPABASE_KEY}`,\n      'Prefer': 'resolution=merge-duplicates,return=representation'\n    },\n    body: JSON.stringify(data)\n  });\n  return r.json();\n}\n\nasync function supabaseSelect(table, filter) {\n  const url = `${SUPABASE_URL}/rest/v1/${table}?${filter}&order=created_at.desc`;\n  const r = await fetch(url, {\n    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }\n  });\n  return r.json();\n}\n\n// \u2500\u2500\u2500 CHAT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction handleKey(e) {\n  if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }\n}\n\nfunction autoResize(el) {\n  el.style.height = 'auto';\n  el.style.height = Math.min(el.scrollHeight, 120) + 'px';\n}\n\nfunction quickSend(text) {\n  document.getElementById('input').value = text;\n  sendMessage();\n}\n\n// --- ROTATING QUICK BUTTONS ---\nconst ALL_QUICK_BTNS = [\n  { emoji: '\ud83d\udcbb', label: 'EPOS crashed', msg: 'My EPOS has crashed mid-service' },\n  { emoji: '\ud83d\udcb3', label: 'Payment terminal offline', msg: 'My payment terminal is offline' },\n  { emoji: '\ud83d\udcf6', label: 'WiFi down', msg: 'WiFi is down in my venue' },\n  { emoji: '\ud83d\udda8\ufe0f', label: 'Kitchen printer issue', msg: 'Kitchen printer not receiving orders' },\n  { emoji: '\ud83d\udcc5', label: 'Reservation system down', msg: 'My reservation system is not working' },\n  { emoji: '\ud83d\udd12', label: 'Can\\'t log in', msg: 'Staff cannot log in to the system' },\n  { emoji: '\ud83d\udcf1', label: 'Contactless not working', msg: 'Contactless payments not working' },\n  { emoji: '\ud83d\udc0c', label: 'EPOS running slow', msg: 'EPOS is running slowly mid-service' },\n  { emoji: '\ud83d\udccb', label: 'Bookings not showing', msg: 'Bookings are not showing on our system' },\n  { emoji: '\ud83d\udd17', label: 'Card reader won\\'t connect', msg: 'Card reader not connecting to EPOS' },\n];\n\n\n// \u2500\u2500\u2500 SOCIAL PROOF \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function loadSocialProof() {\n  try {\n    const r = await fetch(`${SERVER_URL}/analytics`);\n    const data = await r.json();\n    const count = data.totalMessages || 0;\n    const el = document.getElementById('socialProofText');\n    if (el) el.textContent = `${count.toLocaleString()} issues resolved this month`;\n  } catch(e) {\n    const el = document.getElementById('socialProofText');\n    if (el) el.textContent = 'Hospitality tech support, powered by AI';\n  }\n}\n\n// \u2500\u2500\u2500 VENUE PERSONALISATION \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction personaliseWelcome() {\n  if (!user) return;\n  const el = document.getElementById('welcomeVenue');\n  if (el) el.textContent = user.venue ? `Tech support for ${user.venue}.` : 'Ask anything about your hospitality tech.';\n}\n\n// \u2500\u2500\u2500 PREDICTIVE FIXES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nconst TIME_ISSUES = {\n  morning:   [{ icon:'\u2615', text:'Till not opening at start of day', tag:'Common 8\u201311am' }, { icon:'\ud83d\udcf6', text:'WiFi not connecting for staff', tag:'Morning issue' }],\n  lunch:     [{ icon:'\ud83d\udcb3', text:'Payment terminal slow during rush', tag:'Common 12\u20132pm' }, { icon:'\ud83d\udda8\ufe0f', text:'Kitchen printer missing orders', tag:'Rush hour' }],\n  afternoon: [{ icon:'\ud83d\udccb', text:'Reservations not syncing', tag:'Common 2\u20135pm' }, { icon:'\ud83d\udd12', text:'Staff login issues after shift change', tag:'Afternoon' }],\n  evening:   [{ icon:'\ud83d\udcbb', text:'EPOS freezing mid-service', tag:'Common 5\u201310pm' }, { icon:'\ud83d\udcf1', text:'Contactless not working at table', tag:'Service issue' }],\n  latenight: [{ icon:'\ud83d\udd0c', text:'System not closing down properly', tag:'End of night' }, { icon:'\ud83d\udcca', text:'Reports not generating', tag:'Close of day' }],\n};\n\nasync function loadPredictiveFixes() {\n  const hour = new Date().getHours();\n  const day = new Date().getDay(); // 0=Sun, 5=Fri, 6=Sat\n  const isWeekend = day === 0 || day === 5 || day === 6;\n\n  let period = 'morning';\n  if (hour >= 12 && hour < 14) period = 'lunch';\n  else if (hour >= 14 && hour < 17) period = 'afternoon';\n  else if (hour >= 17 && hour < 22) period = 'evening';\n  else if (hour >= 22 || hour < 6) period = 'latenight';\n\n  let issues = [...TIME_ISSUES[period]];\n\n  // Try to enrich with real trending data from analytics\n  try {\n    const r = await fetch(`${SERVER_URL}/analytics`);\n    const data = await r.json();\n    if (data.topTopics && data.topTopics.length > 0) {\n      const topicMap = { 'epos': { icon:'\ud83d\udcbb', text:'EPOS issues' }, 'payment': { icon:'\ud83d\udcb3', text:'Payment terminal problems' }, 'wifi': { icon:'\ud83d\udcf6', text:'WiFi / network issues' }, 'printer': { icon:'\ud83d\udda8\ufe0f', text:'Printer not working' }, 'login': { icon:'\ud83d\udd12', text:'Login / access issues' }, 'reservation': { icon:'\ud83d\udcc5', text:'Reservation system issues' } };\n      data.topTopics.slice(0, 2).forEach(topic => {\n        const key = Object.keys(topicMap).find(k => topic.toLowerCase().includes(k));\n        if (key) issues.unshift({ ...topicMap[key], tag: 'Trending now' });\n      });\n      issues = issues.slice(0, 3);\n    }\n  } catch(e) { /* use time-based only */ }\n\n  const label = document.getElementById('predictLabel');\n  const grid = document.getElementById('predictGrid');\n  const section = document.getElementById('predictSection');\n  if (!grid || !section) return;\n\n  const dayLabel = isWeekend ? 'this weekend' : 'today';\n  if (label) label.textContent = `Common issues ${dayLabel} \u00b7 ${period === 'evening' ? 'evening service' : period}`;\n\n  grid.innerHTML = issues.slice(0,3).map(i =>\n    `<button class=\"predict-btn\" onclick=\"quickSend('${i.text.replace(/'/g,\"\\'\")}')\">\n      <span class=\"predict-icon\">${i.icon}</span>\n      <span>${i.text}</span>\n      <span class=\"predict-tag\">${i.tag}</span>\n    </button>`\n  ).join('');\n  section.style.display = 'block';\n}\n\n// \u2500\u2500\u2500 QR CODE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction renderQRCode() {\n  const el = document.getElementById('qrCode');\n  if (!el || typeof QRCode === 'undefined') return;\n  el.innerHTML = '';\n  new QRCode(el, {\n    text: window.location.href.split('?')[0],\n    width: 96, height: 96,\n    colorDark: '#0d2540',\n    colorLight: '#ffffff',\n    correctLevel: QRCode.CorrectLevel.M\n  });\n}\n\nfunction renderQuickBtns() {\n  const grid = document.getElementById('quickGrid');\n  if (!grid) return;\n  const shuffled = [...ALL_QUICK_BTNS].sort(() => Math.random() - 0.5).slice(0, 4);\n  grid.innerHTML = shuffled.map(b =>\n    `<button class=\"quick-btn\" onclick=\"quickSend('${b.msg.replace(/'/g,\"\\\\'\")}')\"><span class=\"emoji\">${b.emoji}</span>${b.label}</button>`\n  ).join('');\n}\n\n// --- VOICE INPUT ---\nlet recognition = null;\nlet isListening = false;\n\nconst isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !window.MSStream;\n\nfunction toggleMic() {\n  const mic = document.getElementById('mic');\n  const input = document.getElementById('input');\n\n  // iOS Safari \u2014 skip straight to native keyboard mic\n  if (isIOS) {\n    input.focus();\n    showToast('Tap the \ud83c\udfa4 mic on your keyboard to speak');\n    return;\n  }\n\n  // Web Speech API for Chrome desktop / Android\n  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;\n  if (!SR) {\n    input.focus();\n    showToast('Tap the \ud83c\udfa4 mic on your keyboard to speak');\n    return;\n  }\n\n  if (isListening) { recognition?.stop(); return; }\n  recognition = new SR();\n  recognition.lang = 'en-GB';\n  recognition.interimResults = false;\n  recognition.maxAlternatives = 1;\n  recognition.onstart = () => { isListening = true; mic.classList.add('listening'); };\n  recognition.onresult = (e) => {\n    input.value = e.results[0][0].transcript;\n    autoResize(input);\n  };\n  recognition.onend = () => { isListening = false; mic.classList.remove('listening'); };\n  recognition.onerror = () => { isListening = false; mic.classList.remove('listening'); showToast('Could not hear anything \u2014 try again'); };\n  recognition.start();\n}\n\nasync function sendMessage() {\n  const input = document.getElementById('input');\n  const text = input.value.trim();\n  if (!text) return;\n\n  hideWelcome();\n  input.value = '';\n  input.style.height = 'auto';\n  document.getElementById('send').disabled = true;\n\n  addMessage('user', text);\n  messages.push({ role: 'user', content: text });\n\n  const typing = addTyping();\n\n  try {\n    const res = await fetch(`${SERVER_URL}/chat`, {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({ message: text, history: messages.slice(-10), venue: user?.venue, userName: user?.name })\n    });\n    const data = await res.json();\n    const reply = data.response || \"Sorry, I couldn't get a response. Please try again.\";\n    lastBotMsg = reply;\n\n    typing.remove();\n    addMessage('assistant', reply, true);\n    messages.push({ role: 'assistant', content: reply });\n\n    await saveConversation();\n\n  } catch (e) {\n    typing.remove();\n    const errMsg = \"I'm having trouble connecting right now. Please try again in a moment.\";\n    addMessage('assistant', errMsg, true);\n    messages.push({ role: 'assistant', content: errMsg });\n  }\n\n  document.getElementById('send').disabled = false;\n  input.focus();\n}\n\nfunction hideWelcome() {\n  const w = document.getElementById('welcome');\n  if (w) w.remove();\n}\n\nfunction addMessage(role, content, showTicket = false) {\n  const msgs = document.getElementById('messages');\n\n  const wrap = document.createElement('div');\n  wrap.className = `msg ${role}`;\n\n  const avatar = document.createElement('div');\n  avatar.className = 'msg-avatar';\n  if (role === 'assistant') {\n    const img = document.createElement('img');\n    img.src = ICON_URL; img.alt = 'S';\n    avatar.appendChild(img);\n  } else {\n    avatar.textContent = (user?.name || 'You')[0].toUpperCase();\n    avatar.style.background = 'var(--orange)';\n    avatar.style.color = '#fff';\n  }\n\n  const bubble = document.createElement('div');\n  bubble.className = 'msg-bubble';\n  // Render content: make URLs clickable and **text** bold\n  if (role === 'assistant') {\n    // strip markdown links, escape, make URLs clickable\n    let t = content.replace(/\\[([^\\]]+)\\]\\((https?:\\/\\/[^)]+)\\)/g, '$1 $2');\n    t = t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');\n    t = t.replace(/\\*\\*([^*]+)\\*\\*/g,'<strong>$1</strong>');\n    t = t.replace(/(https?:\\/\\/[^\\s<&\"]+)/g,'<a href=\"$1\" target=\"_blank\" rel=\"noopener\" style=\"color:var(--orange);font-weight:600;text-decoration:underline;\">$1</a>');\n    t = t.replace(/(?<![/:\">])(\\b(?:www\\.)?[a-zA-Z0-9-]+\\.(?:com|co\\.uk|io|net|org)(?:\\/[^\\s<&\"]*)?)/g, (m) => {\n      if (t.includes('href=\"https://' + m) || t.includes('href=\"http://' + m)) return m;\n      return '<a href=\"https://' + m + '\" target=\"_blank\" rel=\"noopener\" style=\"color:var(--orange);font-weight:600;text-decoration:underline;\">' + m + '</a>';\n    });\n    bubble.innerHTML = t;\n  } else {\n    bubble.textContent = content;\n  }\n\n  wrap.appendChild(avatar);\n  wrap.appendChild(bubble);\n  msgs.appendChild(wrap);\n\n\n  // Extract and render support links from bot reply\n  if (role === 'assistant') {\n    const urlRegex = /(?:https?:\\/\\/)?(?:www\\.)?[a-zA-Z0-9-]+\\.(?:com|co\\.uk|io|net|org)(?:\\/[^\\s)>\\]\"]*)?/g;\n    const links = [...new Set(content.match(urlRegex) || [])].slice(0, 4);\n    if (links.length) {\n      const map = {'squareup.com':'\ud83d\udce6 Square help','issquareup.com':'\ud83d\udce6 Square status','sumup.com':'\ud83d\udcb3 SumUp help','zettle.com':'\ud83d\udcb3 Zettle help','worldpay.com':'\ud83d\udcb3 Worldpay help','stripe.com':'\ud83d\udcb3 Stripe help','lightspeedhq.com':'\ud83d\udda5 Lightspeed help','tevalis.com':'\ud83d\udda5 Tevalis help','eposnow.com':'\ud83d\udda5 EPOS Now help','vitamojo.com':'\ud83c\udf7d Vita Mojo help','yoello.com':'\ud83d\udcf1 Yoello help','nutritics.com':'\ud83e\udd57 Nutritics help','zonal.co.uk':'\ud83d\udda5 Zonal help'};\n      const label = u => { try { const h = new URL(u).hostname.replace('www.',''); for (const [k,v] of Object.entries(map)) { if (h.includes(k)) return v; } return '\ud83d\udd17 '+h; } catch(e) { return '\ud83d\udd17 Link'; } };\n      const lr = document.createElement('div'); lr.className = 'link-row';\n      lr.innerHTML = links.map(u => '<a class=\"link-pill\" href=\"'+u+'\" target=\"_blank\" rel=\"noopener\">\u2197 '+label(u)+'</a>').join('');\n      msgs.appendChild(lr);\n    }\n  }\n\n  // Add ticket button after bot messages\n  if (role === 'assistant' && showTicket) {\n    const ticketRow = document.createElement('div');\n    ticketRow.className = 'ticket-row';\n    ticketRow.innerHTML = `<button class=\"ticket-btn\" onclick=\"openTicket()\">\ud83c\udfab This didn't solve my issue \u2014 raise a ticket</button>`;\n    msgs.appendChild(ticketRow);\n  }\n\n  msgs.scrollTop = msgs.scrollHeight;\n  return wrap;\n}\n\nfunction addTyping() {\n  const msgs = document.getElementById('messages');\n  const wrap = document.createElement('div');\n  wrap.className = 'typing-bubble';\n\n  const avatar = document.createElement('div');\n  avatar.className = 'msg-avatar';\n  const img = document.createElement('img');\n  img.src = ICON_URL;\n  avatar.appendChild(img);\n\n  const dots = document.createElement('div');\n  dots.className = 'dots';\n  dots.innerHTML = '<div class=\"dot-anim\"></div><div class=\"dot-anim\"></div><div class=\"dot-anim\"></div>';\n\n  wrap.appendChild(avatar);\n  wrap.appendChild(dots);\n  msgs.appendChild(wrap);\n  msgs.scrollTop = msgs.scrollHeight;\n  return wrap;\n}\n\n// \u2500\u2500\u2500 CONVERSATION SAVE \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function saveConversation() {\n  if (!user || messages.length === 0) return;\n  try {\n    const payload = conversationId\n      ? { id: conversationId, messages }\n      : { email: user.email, name: user.name, venue: user.venue, messages, updated_at: new Date().toISOString() };\n    const r = await fetch(`${SERVER_URL}/save-conversation`, {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify(payload)\n    });\n    const data = await r.json();\n    if (data.id && !conversationId) conversationId = data.id;\n  } catch(e) { /* fail silently */ }\n}\n\n// \u2500\u2500\u2500 HISTORY \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nasync function loadHistory() {\n  if (!user) return;\n  try {\n    const rows = await supabaseSelect('conversations', `email=eq.${encodeURIComponent(user.email)}&limit=20`);\n    const body = document.getElementById('histBody');\n    if (!rows || rows.length === 0) {\n      body.innerHTML = '<div class=\"empty-history\">No previous chats yet.</div>';\n      return;\n    }\n    body.innerHTML = '';\n    rows.forEach(row => {\n      const d = new Date(row.updated_at || row.created_at);\n      const dateStr = d.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });\n      const count = (row.messages || []).filter(m => m.role === 'user').length;\n      const item = document.createElement('div');\n      item.className = 'history-item';\n      item.innerHTML = `\n        <div class=\"history-date\">${dateStr}</div>\n        <div class=\"history-preview\">${row.preview || 'Chat session'}</div>\n        <div class=\"history-count\">${count} message${count !== 1 ? 's' : ''}</div>\n      `;\n      item.onclick = () => loadConversation(row);\n      body.appendChild(item);\n    });\n  } catch(e) { /* fail silently */ }\n}\n\nfunction loadConversation(row) {\n  closeHistory();\n  const msgs = document.getElementById('messages');\n  msgs.innerHTML = '';\n  conversationId = row.id;\n  messages = row.messages || [];\n  messages.forEach((m, i) => {\n    const isLast = i === messages.length - 1;\n    addMessage(m.role, m.content, m.role === 'assistant' && isLast);\n  });\n}\n\nfunction openHistory() {\n  loadHistory();\n  document.getElementById('histOverlay').classList.add('open');\n  document.getElementById('histDrawer').classList.add('open');\n}\nfunction closeHistory() {\n  document.getElementById('histOverlay').classList.remove('open');\n  document.getElementById('histDrawer').classList.remove('open');\n}\n\n// \u2500\u2500\u2500 TOPICS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction openTopics() {\n  document.getElementById('topicOverlay').classList.add('open');\n  document.getElementById('topicDrawer').classList.add('open');\n}\nfunction closeTopics() {\n  document.getElementById('topicOverlay').classList.remove('open');\n  document.getElementById('topicDrawer').classList.remove('open');\n}\n\n// \u2500\u2500\u2500 TICKET \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction openTicket() {\n  document.getElementById('ticketNote').value = '';\n  document.getElementById('ticketOverlay').classList.add('open');\n}\nfunction closeTicket() {\n  document.getElementById('ticketOverlay').classList.remove('open');\n}\n\nasync function submitTicket() {\n  const note = document.getElementById('ticketNote').value.trim();\n  const issue = messages.filter(m=>m.role==='user').slice(-1)[0]?.content || '';\n  try {\n    await fetch(`${SERVER_URL}/save-ticket`, {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        email: user.email, name: user.name, venue: user.venue,\n        issue: `Last question: ${issue}` + (note ? `\\n\\nExtra detail: ${note}` : ''),\n        conversation: messages, status: 'open'\n      })\n    });\n    closeTicket();\n    showToast('\u2713 Ticket raised \u2014 we\\'ll be in touch!', 'green');\n  } catch(e) {\n    closeTicket();\n    showToast('Something went wrong, please try again.');\n  }\n}\n\n// \u2500\u2500\u2500 TOAST \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfunction showToast(msg, type = '') {\n  const t = document.getElementById('toast');\n  t.textContent = msg;\n  t.className = `toast ${type} show`;\n  setTimeout(() => { t.className = 'toast'; }, 3500);\n}\n</script>\n</body>\n</html>\n";
const MASTER_ADMIN = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>Stacked \u2014 Master Admin</title>\n<link rel=\"icon\" href=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/Stacked%20(3).svg\">\n<link href=\"https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,600;9..144,700&family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600&display=swap\" rel=\"stylesheet\">\n<style>\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\n:root{\n  --cream:#ede8df;--cream-dark:#e0d9ce;\n  --orange:#f04e1a;--brown:#3a2e24;--brown-mid:#6b5744;\n  --white:#ffffff;--green:#2a9d5c;--red:#d64545;--blue:#2563eb;\n  --shadow:0 2px 16px rgba(58,46,36,0.10);\n  --shadow-lg:0 8px 32px rgba(58,46,36,0.15);\n}\nbody{background:var(--cream);font-family:'DM Sans',sans-serif;color:var(--brown);min-height:100vh}\nheader{background:var(--white);border-bottom:1px solid var(--cream-dark);padding:16px 32px;display:flex;align-items:center;gap:12px;box-shadow:var(--shadow)}\n.header-wordmark{height:28px;object-fit:contain}\n.admin-badge{background:var(--orange);color:#fff;font-size:11px;font-weight:600;padding:3px 8px;border-radius:6px;letter-spacing:0.05em;text-transform:uppercase}\n.master-badge{background:var(--brown);color:#fff;font-size:11px;font-weight:600;padding:3px 8px;border-radius:6px;letter-spacing:0.05em;text-transform:uppercase}\n.container{max-width:1300px;margin:0 auto;padding:32px 24px}\n.page-title{font-family:'Fraunces',serif;font-size:28px;font-weight:700;margin-bottom:6px}\n.page-sub{font-size:14px;color:var(--brown-mid);margin-bottom:32px}\n/* \u2500\u2500 MASTER STATS \u2500\u2500 */\n.master-stats{display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:16px;margin-bottom:36px}\n.stat{background:var(--white);border-radius:16px;padding:20px;box-shadow:var(--shadow)}\n.stat-num{font-family:'Fraunces',serif;font-size:36px;font-weight:700;color:var(--orange)}\n.stat-label{font-size:13px;color:var(--brown-mid);margin-top:4px}\n/* \u2500\u2500 CLIENT CARDS \u2500\u2500 */\n.clients-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:24px;margin-bottom:36px}\n.client-card{background:var(--white);border-radius:20px;box-shadow:var(--shadow);overflow:hidden;transition:box-shadow 0.2s}\n.client-card:hover{box-shadow:var(--shadow-lg)}\n.client-header{padding:20px 24px 16px;border-bottom:1px solid var(--cream-dark);display:flex;align-items:center;justify-content:space-between}\n.client-name-row{display:flex;align-items:center;gap:10px}\n.client-dot{width:10px;height:10px;border-radius:50%;background:var(--green);flex-shrink:0}\n.client-dot.loading{background:var(--cream-dark)}\n.client-name{font-family:'Fraunces',serif;font-size:18px;font-weight:700}\n.client-slug{font-size:12px;color:var(--brown-mid);font-family:monospace;background:var(--cream);padding:2px 8px;border-radius:6px}\n.client-links{display:flex;gap:8px}\n.link-btn{font-size:12px;font-weight:600;padding:5px 12px;border-radius:8px;text-decoration:none;transition:opacity 0.15s;display:flex;align-items:center;gap:4px}\n.link-btn:hover{opacity:0.8}\n.link-btn.chat{background:var(--cream);color:var(--brown)}\n.link-btn.admin{background:var(--orange);color:#fff}\n.client-body{padding:20px 24px}\n.client-stats{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:16px}\n.mini-stat{text-align:center}\n.mini-num{font-family:'Fraunces',serif;font-size:22px;font-weight:700;color:var(--orange)}\n.mini-label{font-size:11px;color:var(--brown-mid);margin-top:2px}\n.client-divider{height:1px;background:var(--cream-dark);margin-bottom:16px}\n.recent-title{font-size:12px;font-weight:600;color:var(--brown-mid);text-transform:uppercase;letter-spacing:0.05em;margin-bottom:8px}\n.recent-item{font-size:13px;padding:6px 0;border-bottom:1px solid var(--cream);display:flex;justify-content:space-between;align-items:flex-start;gap:8px}\n.recent-item:last-child{border-bottom:none}\n.recent-msg{color:var(--brown);flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n.recent-time{color:var(--brown-mid);font-size:11px;flex-shrink:0}\n.badge{display:inline-block;padding:3px 8px;border-radius:6px;font-size:11px;font-weight:600}\n.badge.open{background:#fff3cd;color:#856404}\n.badge.closed{background:#d1e7dd;color:#0a3622}\n.empty-card{color:var(--brown-mid);font-size:13px;text-align:center;padding:16px 0}\n/* \u2500\u2500 STACKED CLIENT (default) \u2500\u2500 */\n.client-card.stacked .client-header{background:var(--cream)}\n.client-card.stacked .mini-num{color:var(--orange)}\n/* \u2500\u2500 BOXPARK CLIENT \u2500\u2500 */\n.client-card.boxpark .client-header{background:#1e1e1e}\n.client-card.boxpark .client-name{color:#ffffff}\n.client-card.boxpark .client-slug{background:#2e2e2e;color:#aaa}\n.client-card.boxpark .client-dot{background:#E31E26}\n.client-card.boxpark .link-btn.admin{background:#E31E26}\n.client-card.boxpark .mini-num{color:#E31E26}\n/* \u2500\u2500 RECENT TICKETS TABLE \u2500\u2500 */\n.section-title{font-family:'Fraunces',serif;font-size:22px;margin-bottom:16px}\n.card{background:var(--white);border-radius:16px;padding:24px;box-shadow:var(--shadow);margin-bottom:24px}\ntable{width:100%;border-collapse:collapse;font-size:14px}\nth{text-align:left;padding:8px 12px;font-weight:600;color:var(--brown-mid);font-size:12px;text-transform:uppercase;letter-spacing:0.05em;border-bottom:2px solid var(--cream-dark)}\ntd{padding:10px 12px;border-bottom:1px solid var(--cream-dark);vertical-align:top}\ntr:last-child td{border-bottom:none}\ntr:hover td{background:var(--cream)}\n.tenant-pill{display:inline-block;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:600;background:var(--cream-dark);color:var(--brown)}\n.tenant-pill.boxpark{background:#1e1e1e;color:#fff}\n.loading-shimmer{background:linear-gradient(90deg,var(--cream) 25%,var(--cream-dark) 50%,var(--cream) 75%);background-size:200% 100%;animation:shimmer 1.5s infinite;border-radius:6px;height:20px;width:80%}\n@keyframes shimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}\n</style>\n</head>\n<body>\n\n<header>\n  <img class=\"header-wordmark\" src=\"https://raw.githubusercontent.com/TOT-STACKED/toast-support-bot/main/assets/Stacked%20(3).svg\" alt=\"Stacked\">\n  <span class=\"admin-badge\">Admin</span>\n  <span class=\"master-badge\">&#x2605; Master</span>\n</header>\n\n<div class=\"container\">\n  <div class=\"page-title\">All clients</div>\n  <div class=\"page-sub\">Across all tenants \u2014 live data</div>\n\n  <!-- MASTER TOTALS -->\n  <div class=\"master-stats\">\n    <div class=\"stat\"><div class=\"stat-num\" id=\"totalConvs\"><div class=\"loading-shimmer\"></div></div><div class=\"stat-label\">Total conversations</div></div>\n    <div class=\"stat\"><div class=\"stat-num\" id=\"totalMsgs\"><div class=\"loading-shimmer\"></div></div><div class=\"stat-label\">Total messages</div></div>\n    <div class=\"stat\"><div class=\"stat-num\" id=\"totalTickets\"><div class=\"loading-shimmer\"></div></div><div class=\"stat-label\">Open tickets</div></div>\n    <div class=\"stat\"><div class=\"stat-num\" id=\"totalClients\">2</div><div class=\"stat-label\">Active clients</div></div>\n  </div>\n\n  <!-- CLIENT CARDS -->\n  <div class=\"clients-grid\" id=\"clientsGrid\">\n\n    <!-- STACKED (default) -->\n    <div class=\"client-card stacked\">\n      <div class=\"client-header\">\n        <div class=\"client-name-row\">\n          <div class=\"client-dot loading\" id=\"dot-stacked\"></div>\n          <div class=\"client-name\">Stacked Chat</div>\n          <span class=\"client-slug\">/</span>\n        </div>\n        <div class=\"client-links\">\n          <a class=\"link-btn chat\" href=\"/\" target=\"_blank\">&#x1F4AC; Chat</a>\n          <a class=\"link-btn admin\" href=\"/admin\" target=\"_blank\">&#x2699;&#xFE0F; Admin</a>\n        </div>\n      </div>\n      <div class=\"client-body\">\n        <div class=\"client-stats\">\n          <div class=\"mini-stat\"><div class=\"mini-num\" id=\"s-convs-stacked\">&mdash;</div><div class=\"mini-label\">Conversations</div></div>\n          <div class=\"mini-stat\"><div class=\"mini-num\" id=\"s-tickets-stacked\">&mdash;</div><div class=\"mini-label\">Open tickets</div></div>\n          <div class=\"mini-stat\"><div class=\"mini-num\" id=\"s-docs-stacked\">&mdash;</div><div class=\"mini-label\">Docs indexed</div></div>\n        </div>\n        <div class=\"client-divider\"></div>\n        <div class=\"recent-title\">Recent conversations</div>\n        <div id=\"recent-stacked\"><div class=\"empty-card\">Loading&hellip;</div></div>\n      </div>\n    </div>\n\n    <!-- BOXPARK -->\n    <div class=\"client-card boxpark\">\n      <div class=\"client-header\">\n        <div class=\"client-name-row\">\n          <div class=\"client-dot loading\" id=\"dot-boxpark\"></div>\n          <div class=\"client-name\">Boxpark</div>\n          <span class=\"client-slug\">/boxpark</span>\n        </div>\n        <div class=\"client-links\">\n          <a class=\"link-btn chat\" href=\"/boxpark\" target=\"_blank\" style=\"background:#2e2e2e;color:#fff\">&#x1F4AC; Chat</a>\n          <a class=\"link-btn admin\" href=\"/boxpark/admin\" target=\"_blank\">&#x2699;&#xFE0F; Admin</a>\n        </div>\n      </div>\n      <div class=\"client-body\">\n        <div class=\"client-stats\">\n          <div class=\"mini-stat\"><div class=\"mini-num\" id=\"s-convs-boxpark\">&mdash;</div><div class=\"mini-label\">Conversations</div></div>\n          <div class=\"mini-stat\"><div class=\"mini-num\" id=\"s-tickets-boxpark\">&mdash;</div><div class=\"mini-label\">Open tickets</div></div>\n          <div class=\"mini-stat\"><div class=\"mini-num\" id=\"s-docs-boxpark\">&mdash;</div><div class=\"mini-label\">Docs indexed</div></div>\n        </div>\n        <div class=\"client-divider\"></div>\n        <div class=\"recent-title\" style=\"color:#888\">Recent conversations</div>\n        <div id=\"recent-boxpark\"><div class=\"empty-card\" style=\"color:#666\">Loading&hellip;</div></div>\n      </div>\n    </div>\n\n  </div>\n\n  <!-- ALL OPEN TICKETS -->\n  <div class=\"section-title\">All open tickets</div>\n  <div class=\"card\">\n    <div id=\"allTickets\"><div class=\"empty-card\">Loading&hellip;</div></div>\n  </div>\n\n</div>\n\n<script>\nfunction esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}\n\nconst CLIENTS = [\n  {slug:'stacked', label:'Stacked Chat', analyticsUrl:'/analytics'},\n  {slug:'boxpark', label:'Boxpark',      analyticsUrl:'/boxpark/analytics'},\n];\n\nlet allData = {};\n\nasync function loadAll(){\n  const results = await Promise.all(CLIENTS.map(c => fetch(c.analyticsUrl).then(r=>r.json()).then(d=>({slug:c.slug,data:d})).catch(e=>({slug:c.slug,data:{error:e.message}}))));\n\n  let totalConvs=0, totalMsgs=0, totalTickets=0;\n  const allTickets = [];\n\n  results.forEach(({slug, data}) => {\n    if (data.error) { document.getElementById('dot-'+slug).style.background='var(--red)'; return; }\n    allData[slug] = data;\n    document.getElementById('dot-'+slug).classList.remove('loading');\n\n    document.getElementById('s-convs-'+slug).textContent = data.totalConvs || 0;\n    document.getElementById('s-tickets-'+slug).textContent = data.openTickets || 0;\n    document.getElementById('s-docs-'+slug).textContent = data.totalDocs || 0;\n\n    totalConvs += data.totalConvs || 0;\n    totalMsgs  += data.totalMessages || 0;\n    totalTickets += data.openTickets || 0;\n\n    // Recent convs\n    const recentEl = document.getElementById('recent-'+slug);\n    const convs = (data.recentConvs||[]).slice(0,4);\n    if (!convs.length) { recentEl.innerHTML='<div class=\"empty-card\">No conversations yet.</div>'; }\n    else {\n      recentEl.innerHTML = convs.map(c => {\n        const first = (c.messages||[]).find(m=>m.role==='user');\n        const d = new Date(c.created_at).toLocaleDateString('en-GB',{day:'numeric',month:'short'});\n        return '<div class=\"recent-item\"><span class=\"recent-msg\">'+esc((first?.content||'').substring(0,55))+'</span><span class=\"recent-time\">'+d+'</span></div>';\n      }).join('');\n    }\n\n    // Collect open tickets\n    (data.tickets||[]).filter(t=>t.status==='open').forEach(t => allTickets.push({...t, _client:slug}));\n  });\n\n  document.getElementById('totalConvs').textContent = totalConvs;\n  document.getElementById('totalMsgs').textContent = totalMsgs;\n  document.getElementById('totalTickets').textContent = totalTickets;\n\n  // All open tickets table\n  const tt = document.getElementById('allTickets');\n  if (!allTickets.length) { tt.innerHTML='<div class=\"empty-card\">No open tickets across any client. &#x1F389;</div>'; }\n  else {\n    allTickets.sort((a,b)=>new Date(b.created_at)-new Date(a.created_at));\n    tt.innerHTML='<table><thead><tr><th>Client</th><th>Name</th><th>Venue</th><th>Issue</th><th>Date</th></tr></thead><tbody>'\n      + allTickets.map(t =>\n        '<tr>'\n        +'<td><span class=\"tenant-pill '+t._client+'\">'+esc(t._client)+'</span></td>'\n        +'<td><strong>'+esc(t.name||'')+'</strong><br><small>'+esc(t.email||'')+'</small></td>'\n        +'<td>'+esc(t.venue||'')+'</td>'\n        +'<td style=\"max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap\">'+esc(t.issue||'')+'</td>'\n        +'<td>'+new Date(t.created_at).toLocaleDateString('en-GB')+'</td>'\n        +'</tr>'\n      ).join('')\n      +'</tbody></table>';\n  }\n}\n\nloadAll();\n// Auto-refresh every 60 seconds\nsetInterval(loadAll, 60000);\n</script>\n</body>\n</html>";

