function stripHtml(html) {
  // Remove scripts, styles, nav, footer, header tags and their contents
  let text = html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, ' ')
    .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, ' ')
    .replace(/<header[^>]*>[\s\S]*?<\/header>/gi, ' ')
    .replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, ' ')
    // Convert block elements to newlines for readability
    .replace(/<\/?(p|div|h[1-6]|li|tr|br|section|article)[^>]*>/gi, '\n')
    // Strip remaining tags
    .replace(/<[^>]+>/g, ' ')
    // Decode common HTML entities
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ').replace(/&quot;/g, '"').replace(/&#39;/g, "'")
    .replace(/&[a-z]+;/gi, ' ')
    // Collapse whitespace
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  return text;
}

function extractTitle(html) {
  const m = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  return m ? m[1].trim().replace(/[^a-zA-Z0-9 \-_.,]/g, ' ').replace(/\s+/g,' ').trim() : null;
}

function chunkText(text, filename) {
  const chunkSize = 1200;
  const chunks = [];
  for (let i = 0; i < text.length; i += chunkSize) {
    chunks.push({filename, content:text.substring(i, i+chunkSize), chunk_index:chunks.length});
  }
  return chunks;
}

async function fetchPlaylistItems(playlistId, apiKey) {
  const https = require('https'); const ids = []; let pageToken = '';
  do {
    const path = '/youtube/v3/playlistItems?part=contentDetails&maxResults=50&playlistId='
      + encodeURIComponent(playlistId) + '&key=' + apiKey + (pageToken ? '&pageToken='+pageToken : '');
    const data = await new Promise((res,rej) => {
      https.request({hostname:'www.googleapis.com',path,method:'GET'},(resp)=>{
        let d=''; resp.on('data',c=>d+=c); resp.on('end',()=>{try{res(JSON.parse(d));}catch(e){rej(e);}});
      }).on('error',rej).end();
    });
    if (data.error) throw new Error('YouTube API: '+data.error.message);
    (data.items||[]).forEach(item => { if (item.contentDetails&&item.contentDetails.videoId) ids.push(item.contentDetails.videoId); });
    pageToken = data.nextPageToken || '';
  } while (pageToken);
  return ids;
}

async function fetchYouTubeTranscript(videoId) {
  const https = require('https');
  const html = await new Promise((res,rej) => {
    https.request({hostname:'www.youtube.com',path:'/watch?v='+videoId,method:'GET',
      headers:{'User-Agent':'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120 Safari/537.36','Accept-Language':'en-GB,en;q=0.9'}
    },(resp)=>{let d=''; resp.on('data',c=>d+=c); resp.on('end',()=>res(d));}).on('error',rej).end();
  });
  const titleMatch = html.match(/<title>([^<]+)<\/title>/);
  const title = titleMatch ? titleMatch[1].replace(' - YouTube','').trim() : videoId;
  const captionMatch = html.match(/"captionTracks":\[\{"baseUrl":"([^"]+)"/);
  if (!captionMatch) throw new Error('No auto-captions available for this video');
  const captionUrl = captionMatch[1].replace(/\\u0026/g,'&').replace(/\\u003d/g,'=').replace(/\\u003c/g,'<');
  const captionXml = await new Promise((res,rej) => {
    const u = new URL(captionUrl+'&lang=en');
    https.request({hostname:u.hostname,path:u.pathname+u.search,method:'GET',headers:{'User-Agent':'Mozilla/5.0'}},(resp)=>{
      if (resp.statusCode>=300&&resp.statusCode<400&&resp.headers.location) {
        https.get(resp.headers.location,{headers:{'User-Agent':'Mozilla/5.0'}},(r2)=>{let d='';r2.on('data',c=>d+=c);r2.on('end',()=>res(d));}).on('error',rej); return;
      }
      let d=''; resp.on('data',c=>d+=c); resp.on('end',()=>res(d));
    }).on('error',rej).end();
  });
  const transcript = captionXml
    .replace(/<text[^>]*>/g,' ').replace(/<\/text>/g,' ').replace(/<[^>]+>/g,' ')
    .replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&#39;/g,"'").replace(/&quot;/g,'"')
    .replace(/\s+/g,' ').trim();
  if (transcript.length < 50) throw new Error('Captions returned empty content');
  return { title, transcript: '=== '+title+' ===\n\n'+transcript };
}

